function getJournalMemoryInsightClasses(
  severity: JournalMemoryInsight["severity"],
) {
  switch (severity) {
    case "positive":
      return "border-emerald-300/[0.16] bg-emerald-300/[0.055] text-emerald-100";
    case "critical":
      return "border-rose-300/[0.18] bg-rose-400/[0.065] text-rose-100";
    case "warning":
      return "border-amber-300/[0.18] bg-amber-400/[0.065] text-amber-100";
    case "info":
    default:
      return "border-cyan-300/[0.14] bg-cyan-300/[0.045] text-cyan-100";
  }
}

function getJournalMemoryInsightDotClass(
  severity: JournalMemoryInsight["severity"],
) {
  switch (severity) {
    case "positive":
      return "bg-emerald-300/84";
    case "critical":
      return "bg-rose-300/88";
    case "warning":
      return "bg-amber-300/88";
    case "info":
    default:
      return "bg-cyan-300/84";
  }
}

