type MagicTradeWsCandleEntry = Partial<{
  c: number | string;
  i: string;
  s: string;
  t: number;
}>;

type MagicTradeWsCandleMessage = {
  channel: "candle";
  data: MagicTradeWsCandleEntry | MagicTradeWsCandleEntry[];
};

type MagicTradeWsActiveAssetCtxMessage = {
  channel: "activeAssetCtx";
  data: {
    coin?: string;
    ctx?: {
      markPx?: number | string;
    };
  };
};

function isMagicTradeWsCandleMessage(
  payload: unknown,
): payload is MagicTradeWsCandleMessage {
  return (
    typeof payload === "object" &&
    payload !== null &&
    "channel" in payload &&
    payload.channel === "candle" &&
    "data" in payload
  );
}

function isMagicTradeWsActiveAssetCtxMessage(
  payload: unknown,
): payload is MagicTradeWsActiveAssetCtxMessage {
  return (
    typeof payload === "object" &&
    payload !== null &&
    "channel" in payload &&
    payload.channel === "activeAssetCtx" &&
    "data" in payload
  );
}

