function getAvatarExpSourceTone(
  bundle: StoredBaselineImportBundle,
): AvatarExpSource["tone"] {
  const profile = bundle.result.profile;

  if (profile.dataQuality.length > 0) {
    return "warning";
  }

  if (profile.totals.netPnl > 0) {
    return "positive";
  }

  if (profile.totals.netPnl < 0) {
    return "negative";
  }

  return "neutral";
}

function getAvatarSoulFindingTone(finding: DiagnosisFinding): AvatarSoulTone {
  switch (finding.severity) {
    case "positive":
      return "positive";
    case "critical":
      return "critical";
    case "warning":
      return "warning";
    default:
      return "neutral";
  }
}

function getAvatarSoulStateTone(state: string): AvatarSoulTone {
  switch (state) {
    case "Warning":
      return "warning";
    case "Insight Available":
      return "positive";
    default:
      return "neutral";
  }
}

function formatAvatarSoulRecommendationTitle(type: string) {
  switch (type) {
    case "cooldown_after_loss":
      return "Cooldown After Loss";
    case "max_trades_per_day":
      return "Trade Cap";
    case "show_less_warnings":
      return "Reduce Warning Noise";
    default:
      return type.replace(/_/g, " ");
  }
}

function getAvatarArmoryToneForState(
  state: AvatarArmoryRuleState,
): AvatarArmoryTone {
  switch (state) {
    case "locked":
    case "triggered":
      return "warning";
    case "overridden":
      return "overridden";
    case "active":
    case "armed":
      return "active";
    default:
      return "neutral";
  }
}

function getAvatarArmoryState(
  enabled: boolean,
  state?: string | null,
): AvatarArmoryRuleState {
  if (!enabled) {
    return "inactive";
  }

  if (
    state === "active" ||
    state === "armed" ||
    state === "triggered" ||
    state === "locked" ||
    state === "overridden"
  ) {
    return state;
  }

  return "active";
}

function getAvatarArmoryOverviewTone({
  hardLockActive,
  statusLabel,
}: {
  hardLockActive: boolean;
  statusLabel: string;
}): AvatarArmoryTone {
  if (hardLockActive || statusLabel === "Blocked") {
    return "warning";
  }

  return statusLabel === "Active" ? "active" : "neutral";
}

function getAvatarArmoryMetricTone(value: number): AvatarArmoryTone {
  if (value < 0) {
    return "warning";
  }

  if (value > 0) {
    return "active";
  }

  return "neutral";
}

function getDisciplineSwitchClass(
  active: boolean,
  tone: "amber" | "red" = "amber",
) {
  if (active) {
    return tone === "red"
      ? "border-red-200/24 bg-red-500/28 shadow-[0_0_16px_rgba(239,68,68,0.16),inset_0_1px_0_rgba(255,255,255,0.12)]"
      : "border-cyan-200/24 bg-cyan-300/24 shadow-[0_0_16px_rgba(34,211,238,0.15),inset_0_1px_0_rgba(255,255,255,0.12)]";
  }

  return "border-white/24 bg-white/[0.075] shadow-[inset_0_1px_0_rgba(255,255,255,0.08)] hover:border-cyan-200/24 hover:bg-cyan-300/[0.09]";
}

function getDisciplineSwitchKnobClass(active: boolean) {
  return active
    ? "translate-x-[24px] bg-cyan-50 shadow-[0_0_14px_rgba(207,250,254,0.36)]"
    : "translate-x-0 bg-slate-300/90";
}

function DisciplineRuleSwitch({
  ariaLabel,
  checked,
  onToggle,
  tone = "amber",
}: {
  ariaLabel: string;
  checked: boolean;
  onToggle: () => void;
  tone?: "amber" | "red";
}) {
  return (
    <button
      type="button"
      role="switch"
      aria-label={ariaLabel}
      aria-checked={checked}
      className={`relative inline-flex h-8 w-[58px] shrink-0 cursor-pointer items-center rounded-full border p-[3px] transition ${getDisciplineSwitchClass(
        checked,
        tone,
      )}`}
      onClick={() => {
        onToggle();
      }}
    >
      <span
        className={`pointer-events-none h-6 w-6 rounded-full transition-transform duration-200 ${getDisciplineSwitchKnobClass(
          checked,
        )}`}
      />
    </button>
  );
}

