type MagicTradePreviewChunk = {
  label: string;
  tone?: "asset" | "action";
};

type MagicTradePreviewPhase = "reveal" | "hold" | "hide";

const MAGIC_TRADE_PREVIEW_SENTENCES: MagicTradePreviewChunk[][] = [
  [
    { label: "If" },
    { label: "BTC", tone: "asset" },
    { label: "closes below" },
    { label: "$___" },
    { label: "->" },
    { label: "Short", tone: "action" },
    { label: "SOL", tone: "asset" },
    { label: "2x" },
  ],
  [
    { label: "If" },
    { label: "SOL", tone: "asset" },
    { label: "closes above" },
    { label: "$___" },
    { label: "->" },
    { label: "Long", tone: "action" },
    { label: "SOL", tone: "asset" },
    { label: "3x" },
  ],
  [
    { label: "If" },
    { label: "BTC", tone: "asset" },
    { label: "touches" },
    { label: "$___" },
    { label: "->" },
    { label: "Move stop" },
    { label: "to breakeven", tone: "action" },
  ],
  [
    { label: "If" },
    { label: "ETH", tone: "asset" },
    { label: "crosses above" },
    { label: "$___" },
    { label: "->" },
    { label: "Open a long", tone: "action" },
    { label: "on" },
    { label: "BTC", tone: "asset" },
  ],
];

function MagicTradePreview() {
  const [sentenceIndex, setSentenceIndex] = useState(0);
  const [visibleChunkCount, setVisibleChunkCount] = useState(0);
  const [animationPhase, setAnimationPhase] =
    useState<MagicTradePreviewPhase>("reveal");
  const [isReducedMotion, setIsReducedMotion] = useState(false);

  useEffect(() => {
    const mediaQuery = window.matchMedia("(prefers-reduced-motion: reduce)");
    const updateReducedMotion = () => {
      setIsReducedMotion(mediaQuery.matches);
    };

    updateReducedMotion();
    mediaQuery.addEventListener("change", updateReducedMotion);

    return () => {
      mediaQuery.removeEventListener("change", updateReducedMotion);
    };
  }, []);

  useEffect(() => {
    if (isReducedMotion) {
      setSentenceIndex(0);
      setAnimationPhase("hold");
      setVisibleChunkCount(MAGIC_TRADE_PREVIEW_SENTENCES[0]?.length ?? 0);
      return;
    }

    const currentSentence = MAGIC_TRADE_PREVIEW_SENTENCES[sentenceIndex] ?? [];
    const sentenceLength = currentSentence.length;
    let timeoutId: number;

    if (animationPhase === "reveal") {
      if (visibleChunkCount < sentenceLength) {
        timeoutId = window.setTimeout(() => {
          setVisibleChunkCount((currentCount) =>
            Math.min(currentCount + 1, sentenceLength),
          );
        }, 105);
      } else {
        timeoutId = window.setTimeout(() => {
          setAnimationPhase("hold");
        }, 120);
      }
    } else if (animationPhase === "hold") {
      timeoutId = window.setTimeout(() => {
        setAnimationPhase("hide");
      }, 2850);
    } else if (visibleChunkCount > 0) {
      timeoutId = window.setTimeout(() => {
        setVisibleChunkCount((currentCount) => Math.max(currentCount - 1, 0));
      }, 72);
    } else {
      timeoutId = window.setTimeout(() => {
        setSentenceIndex(
          (currentIndex) =>
            (currentIndex + 1) % MAGIC_TRADE_PREVIEW_SENTENCES.length,
        );
        setVisibleChunkCount(0);
        setAnimationPhase("reveal");
      }, 170);
    }

    return () => {
      window.clearTimeout(timeoutId);
    };
  }, [animationPhase, isReducedMotion, sentenceIndex, visibleChunkCount]);

  const sentence =
    MAGIC_TRADE_PREVIEW_SENTENCES[isReducedMotion ? 0 : sentenceIndex] ?? [];

  return (
    <div className="portal-magic-preview" aria-hidden="true">
      <div className="portal-magic-preview-line">
        {sentence.map((chunk, index) => (
          <span
            key={`${sentenceIndex}-${chunk.label}-${index}`}
            className={`portal-magic-preview-chunk ${
              index < visibleChunkCount
                ? "portal-magic-preview-chunk-visible"
                : ""
            } ${
              chunk.tone === "asset"
                ? "portal-magic-preview-chunk-asset"
                : chunk.tone === "action"
                  ? "portal-magic-preview-chunk-action"
                  : ""
            }`}
            style={
              {
                "--portal-magic-preview-index": index,
              } as CSSProperties
            }
          >
            {chunk.label}
          </span>
        ))}
      </div>
    </div>
  );
}

