type PortalOrderBookPanelProps = {
  activeSymbol: HyperliquidSymbol;
  orderBook: HyperliquidOrderBook | null;
  recentTrades: HyperliquidRecentTrades | null;
};

function PortalOrderBookPanel({
  activeSymbol,
  orderBook,
  recentTrades,
}: PortalOrderBookPanelProps) {
  const baseAsset = activeSymbol.replace("-USD", "");
  const [activeView, setActiveView] = useState<"book" | "trades">("book");
  const visibleAsks = (orderBook?.asks ?? []).slice(0, 5).reverse();
  const visibleBids = (orderBook?.bids ?? []).slice(0, 5);
  const visibleTrades = (recentTrades?.trades ?? []).slice(0, 12);
  const midpoint =
    orderBook?.asks[0] && orderBook?.bids[0]
      ? (orderBook.asks[0].price + orderBook.bids[0].price) / 2
      : null;
  const maxTotal = Math.max(
    ...visibleAsks.map((level) => level.totalUsd),
    ...visibleBids.map((level) => level.totalUsd),
    0,
  );

  return (
    <div className="portal-drawer-enter relative isolate flex h-full min-h-0 flex-col overflow-hidden rounded-portal-panel border border-cyan-100/[0.045] bg-[linear-gradient(180deg,rgba(7,14,24,0.22),rgba(3,6,12,0.14))] shadow-[var(--portal-shadow-control)] portal-clip-panel">
      <div className="pointer-events-none absolute inset-x-4 top-0 h-px bg-gradient-to-r from-transparent via-cyan-200/22 to-transparent" />
      <div className="flex shrink-0 items-center border-b border-white/[0.06]">
        <div className="grid min-w-0 flex-1 grid-cols-2 text-center text-[13px] font-semibold">
          <button
            type="button"
            className={`py-2.5 transition ${
              activeView === "book"
                ? "border-b border-cyan-300/74 text-cyan-50"
                : "text-white/36 hover:text-white/68"
            }`}
            onClick={() => setActiveView("book")}
          >
            Order Book
          </button>
          <button
            type="button"
            className={`py-2.5 transition ${
              activeView === "trades"
                ? "border-b border-cyan-300/74 text-cyan-50"
                : "text-white/36 hover:text-white/68"
            }`}
            onClick={() => setActiveView("trades")}
          >
            Trades
          </button>
        </div>
      </div>

      {activeView === "book" ? (
        <>
          <div className="flex shrink-0 items-center justify-between border-b border-white/[0.045] px-4 py-1 font-mono text-[10px] text-white/46">
            <span>0.000001</span>
            <span>{baseAsset}/USDC</span>
          </div>

          <div className="grid shrink-0 grid-cols-[1fr_0.85fr_0.85fr] px-4 pb-1 pt-1.5 text-[10px] font-medium text-white/38">
            <span>Price</span>
            <span className="text-right">Size (USDC)</span>
            <span className="text-right">Total (USDC)</span>
          </div>

          <div className="grid min-h-0 flex-1 grid-rows-[minmax(0,1fr)_auto_minmax(0,1fr)] overflow-hidden px-2 pb-2">
            <div className="flex min-h-0 flex-col justify-end gap-0.5 overflow-hidden">
              {visibleAsks.map((level) => (
                <OrderBookRow
                  key={`ask-${level.price}`}
                  level={level}
                  maxTotal={maxTotal}
                  side="ask"
                />
              ))}
            </div>

            <div className="my-1 grid grid-cols-[1fr_auto_auto_auto] items-center gap-3 rounded-portal-control bg-white/[0.055] px-3 py-1.5 font-mono text-[11px] text-white/86">
              <span>Mid {formatOrderBookPrice(midpoint)}</span>
              <span>Spread</span>
              <span>{formatOrderBookPrice(orderBook?.spread ?? null)}</span>
              <span>
                {formatOrderBookPercent(orderBook?.spreadPercent ?? null)}
              </span>
            </div>

            <div className="flex min-h-0 flex-col gap-0.5 overflow-hidden">
              {visibleBids.map((level) => (
                <OrderBookRow
                  key={`bid-${level.price}`}
                  level={level}
                  maxTotal={maxTotal}
                  side="bid"
                />
              ))}
            </div>

            {!orderBook ? (
              <div className="flex h-full items-center justify-center text-[12px] text-white/40">
                Loading Hyperliquid book...
              </div>
            ) : null}
          </div>
        </>
      ) : (
        <div className="min-h-0 flex-1 overflow-hidden px-3 py-2">
          <div className="grid grid-cols-[1fr_0.8fr_0.8fr_0.75fr] px-1 pb-1 text-[10px] font-medium text-white/38">
            <span>Price</span>
            <span className="text-right">Size (USDC)</span>
            <span className="text-right">Size ({baseAsset})</span>
            <span className="text-right">Time</span>
          </div>
          <div className="space-y-0.5">
            {visibleTrades.map((trade) => (
              <RecentTradeRow key={trade.id} trade={trade} />
            ))}
          </div>
          {visibleTrades.length === 0 ? (
            <div className="flex h-full items-center justify-center text-[12px] text-white/40">
              Loading Hyperliquid trades...
            </div>
          ) : null}
        </div>
      )}
    </div>
  );
}

type OrderBookRowProps = {
  level: HyperliquidOrderBook["asks"][number];
  maxTotal: number;
  side: "ask" | "bid";
};

function OrderBookRow({ level, maxTotal, side }: OrderBookRowProps) {
  const depthPercent =
    maxTotal > 0
      ? Math.min(100, Math.max(4, (level.totalUsd / maxTotal) * 100))
      : 0;
  const depthTone =
    side === "ask" ? "bg-rose-400/[0.15]" : "bg-emerald-400/[0.14]";
  const priceTone = side === "ask" ? "text-[#FF6B8A]" : "text-[#13C8A1]";

  return (
    <div className="relative grid h-[21px] grid-cols-[1fr_0.85fr_0.85fr] items-center overflow-hidden rounded-portal-chip px-3 font-mono text-[11px] leading-[1.25]">
      <span
        className={`pointer-events-none absolute inset-y-0 left-0 ${depthTone}`}
        style={{ width: `${depthPercent}%` }}
        aria-hidden="true"
      />
      <span className={`relative z-10 ${priceTone}`}>
        {formatOrderBookPrice(level.price)}
      </span>
      <span className="relative z-10 text-right text-white/82">
        {formatOrderBookSize(level.sizeUsd)}
      </span>
      <span className="relative z-10 text-right text-white/82">
        {formatOrderBookSize(level.totalUsd)}
      </span>
    </div>
  );
}

type RecentTradeRowProps = {
  trade: HyperliquidRecentTrades["trades"][number];
};

function RecentTradeRow({ trade }: RecentTradeRowProps) {
  const priceTone = trade.side === "buy" ? "text-[#13C8A1]" : "text-[#FF6B8A]";

  return (
    <div className="grid h-[21px] grid-cols-[1fr_0.8fr_0.8fr_0.75fr] items-center rounded-portal-chip px-1 font-mono text-[11px] leading-[1.25] text-white/78">
      <span className={priceTone}>{formatOrderBookPrice(trade.price)}</span>
      <span className="text-right">{formatOrderBookSize(trade.sizeUsd)}</span>
      <span className="text-right">{formatOrderBookBaseSize(trade.size)}</span>
      <span className="text-right text-white/36">
        {formatRecentTradeTime(trade.time)}
      </span>
    </div>
  );
}

function formatOrderBookPrice(value: number | null) {
  if (value === null || !Number.isFinite(value)) {
    return "--";
  }

  return new Intl.NumberFormat("en-US", {
    maximumFractionDigits: value >= 1_000 ? 1 : value >= 1 ? 3 : 6,
    minimumFractionDigits: value >= 1_000 ? 1 : 0,
  }).format(value);
}

function formatOrderBookSize(value: number | null) {
  if (value === null || !Number.isFinite(value)) {
    return "--";
  }

  return new Intl.NumberFormat("en-US", {
    maximumFractionDigits: value >= 1 ? 3 : 5,
  }).format(value);
}

function formatOrderBookBaseSize(value: number | null) {
  if (value === null || !Number.isFinite(value)) {
    return "--";
  }

  return new Intl.NumberFormat("en-US", {
    maximumFractionDigits: 5,
  }).format(value);
}

function formatRecentTradeTime(value: number | null) {
  if (value === null || !Number.isFinite(value)) {
    return "--:--";
  }

  return new Intl.DateTimeFormat("en-US", {
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
  }).format(new Date(value));
}

function formatOrderBookPercent(value: number | null) {
  if (value === null || !Number.isFinite(value)) {
    return "--";
  }

  return `${new Intl.NumberFormat("en-US", {
    maximumFractionDigits: 3,
    minimumFractionDigits: 3,
  }).format(value)}%`;
}

