  "w-full rounded-portal-panel border border-sky-300/[0.18] bg-[#080d18]/[0.84] px-4 py-3 text-[13px] font-semibold text-white/[0.90] shadow-[0_0_18px_rgba(59,130,246,0.08),inset_0_1px_0_rgba(255,255,255,0.08)] outline-none transition [color-scheme:dark] placeholder:text-white/[0.46] focus:border-cyan-300/[0.50] focus:bg-[#0b1220]/[0.96] focus:text-white focus:shadow-[0_0_0_1px_rgba(51,245,255,0.14),0_0_24px_rgba(51,245,255,0.12),inset_0_1px_0_rgba(255,255,255,0.09)] disabled:cursor-not-allowed disabled:border-white/[0.04] disabled:bg-white/[0.035] disabled:text-white/[0.34]";
const FALLBACK_MARKET_METADATA = getPortalMarketMetadata(
  hyperliquidSymbols.map(toHyperliquidMarketMetadata),
);
type MagicTradeComposerStage =
  | "source-asset"
  | "source-event"
  | "event-modifier"
  | "level"
  | "timeframe"
  | "target-action"
  | "target-asset"
  | "enter-direction"
  | "enter-leverage"
  | "enter-size"
  | "position-side"
  | "reduce-percent"
  | "fire-behavior"
  | "execution-mode"
  | "review";
type MagicTradeEventRoot = "crosses" | "closes" | null;
const MAGIC_TRADE_STAGE_INDEX: Record<MagicTradeComposerStage, number> = {
  "source-asset": 0,
  "source-event": 1,
  "event-modifier": 2,
  level: 3,
  timeframe: 4,
  "target-action": 5,
  "target-asset": 6,
  "enter-direction": 7,
  "enter-leverage": 8,
  "enter-size": 9,
  "position-side": 10,
  "reduce-percent": 11,
  "fire-behavior": 12,
  "execution-mode": 13,
  review: 14,
};
const TAG_ALONG_WATCHER_TICK_MS = 5_000;

function formatTagAlongComposerSymbol(symbol: TagAlongSymbol | "") {
  return symbol ? symbol.replace(/-USD$/i, "") : "";
}

function getMagicTradeConditionRoot(
  conditionType: TagAlongBuilderConditionType,
): MagicTradeEventRoot {
  if (
    conditionType === "price-crosses-above-level" ||
    conditionType === "price-crosses-below-level"
  ) {
    return "crosses";
  }

  if (
    conditionType === "candle-closes-above-level" ||
    conditionType === "candle-closes-below-level"
  ) {
    return "closes";
  }

  return null;
}

function getMagicTradeFirstIncompleteStage(
  draft?: TagAlongRuleBuilderDraft | null,
): MagicTradeComposerStage {
  if (!draft?.sourceSymbol) {
    return "source-asset";
  }

  if (!draft.sourceConditionType) {
    return "source-event";
  }

  if (
    draft.sourceConditionType !== "price-touches-level" &&
    !(
      draft.sourceConditionType === "price-crosses-above-level" ||
      draft.sourceConditionType === "price-crosses-below-level" ||
      draft.sourceConditionType === "candle-closes-above-level" ||
      draft.sourceConditionType === "candle-closes-below-level"
    )
  ) {
    return "event-modifier";
  }

  if (!draft.level) {
    return "level";
  }

  if (
    sourceConditionRequiresTimeframe(draft.sourceConditionType) &&
    !draft.timeframe
  ) {
    return "timeframe";
  }

  if (!draft.targetActionType) {
    return "target-action";
  }

  if (draft.targetActionType === "enter-market") {
    if (!draft.targetSymbol) {
      return "target-asset";
    }

    if (draft.enterDirection !== "long" && draft.enterDirection !== "short") {
      return "enter-direction";
    }

    if (!draft.enterLeverage) {
      return "enter-leverage";
    }

    if (!draft.enterSizeUsd) {
      return "enter-size";
    }

    return "review";
  }

  const usesPositionTargets =
    draft.targetActionType === "close-position" ||
    draft.targetActionType === "reduce-position-percent" ||
    draft.targetActionType === "move-stop-to-break-even";

  if (
    usesPositionTargets &&
    (!draft.targetActions || draft.targetActions.length === 0)
  ) {
    return "target-asset";
  }

  if (
    draft.targetActionType !== "cancel-all-symbol-orders" &&
    !usesPositionTargets &&
    !draft.targetSymbol
  ) {
    return "target-asset";
  }

  if (
    (draft.targetActionType === "close-position" ||
      draft.targetActionType === "reduce-position-percent") &&
    (!draft.targetActions || draft.targetActions.length === 0) &&
    !draft.positionSide
  ) {
    return "position-side";
  }

  if (
    draft.targetActionType === "reduce-position-percent" &&
    !draft.reducePercent
  ) {
    return "reduce-percent";
  }

  return "review";
}

function getMagicTradeNextStage(
  draft: TagAlongRuleBuilderDraft,
  stage: MagicTradeComposerStage,
) {
  switch (stage) {
    case "source-asset":
      return "source-event";
    case "source-event":
      return draft.sourceConditionType === "price-touches-level"
        ? "level"
        : "event-modifier";
    case "event-modifier":
      return "level";
    case "level":
      return sourceConditionRequiresTimeframe(draft.sourceConditionType)
        ? "timeframe"
        : "target-action";
    case "timeframe":
      return "target-action";
    case "target-action":
      return draft.targetActionType === "cancel-all-symbol-orders"
        ? "review"
        : "target-asset";
    case "target-asset":
      if (draft.targetActionType === "enter-market") {
        return "enter-direction";
      }
      return draft.targetActionType === "reduce-position-percent"
        ? "reduce-percent"
        : "review";
    case "enter-direction":
      return "enter-leverage";
    case "enter-leverage":
      return "enter-size";
    case "enter-size":
      return "review";
    case "position-side":
      return draft.targetActionType === "reduce-position-percent"
        ? "reduce-percent"
        : "review";
    case "reduce-percent":
      return "review";
    case "fire-behavior":
      return "review";
    case "execution-mode":
      return "review";
    case "review":
      return "review";
  }
}

function getMagicTradePreviousStage(
  draft: TagAlongRuleBuilderDraft,
  stage: MagicTradeComposerStage,
) {
  switch (stage) {
    case "source-asset":
      return "source-asset";
    case "source-event":
      return "source-asset";
    case "event-modifier":
      return "source-event";
    case "level":
      return draft.sourceConditionType === "price-touches-level"
        ? "source-event"
        : "event-modifier";
    case "timeframe":
      return "level";
    case "target-action":
      return sourceConditionRequiresTimeframe(draft.sourceConditionType)
        ? "timeframe"
        : "level";
    case "target-asset":
      return draft.targetActionType === "cancel-all-symbol-orders"
        ? "target-action"
        : "target-action";
    case "enter-direction":
      return "target-asset";
    case "enter-leverage":
      return "enter-direction";
    case "enter-size":
      return "enter-leverage";
    case "position-side":
      return "target-asset";
    case "reduce-percent":
      return "target-asset";
    case "fire-behavior":
      return draft.targetActionType === "enter-market"
        ? "enter-size"
        : draft.targetActionType === "reduce-position-percent"
          ? "reduce-percent"
          : draft.targetActionType === "cancel-all-symbol-orders"
            ? "target-action"
            : "target-asset";
    case "execution-mode":
      return "review";
    case "review":
      return draft.targetActionType === "enter-market"
        ? "enter-size"
        : draft.targetActionType === "reduce-position-percent"
          ? "reduce-percent"
          : draft.targetActionType === "cancel-all-symbol-orders"
            ? "target-action"
            : "target-asset";
  }
}

function normalizeTagAlongComposerSymbolInput(
  value: string,
): TagAlongSymbol | "" {
  const cleanedValue = value
    .trim()
    .toUpperCase()
    .replace(/[^A-Z0-9-]/g, "");

  if (!cleanedValue) {
    return "";
  }

  return (
    cleanedValue.endsWith("-USD") ? cleanedValue : `${cleanedValue}-USD`
  ) as TagAlongSymbol;
}

function getMagicTradeChartSymbol(
  symbol: TagAlongSymbol | "",
): PortalChartSymbol | null {
  return symbol ? (symbol as PortalChartSymbol) : null;
}

function getMagicTradeMaxLeverageInt(maxLeverage: number | null | undefined) {
  return Number.isFinite(maxLeverage) && maxLeverage && maxLeverage > 0
    ? Math.floor(maxLeverage)
    : null;
}

function clampMagicTradeLeverage(value: number, maxLeverage: number) {
  return Math.max(1, Math.min(maxLeverage, Math.round(value)));
}

function parseStoredTradeLeverageBySymbol(raw: string | null) {
  if (!raw) {
    return {};
  }

  const parsedValue = JSON.parse(raw) as unknown;

  if (
    !parsedValue ||
    typeof parsedValue !== "object" ||
    Array.isArray(parsedValue)
  ) {
    return {};
  }

  const supportedSymbols = new Set(
    hyperliquidSymbols.map((market) => market.symbol),
  );

  return Object.entries(parsedValue).reduce<
    Partial<Record<HyperliquidSymbol, number>>
  >((storedLeverageBySymbol, [symbol, leverage]) => {
    const normalizedSymbol = symbol.trim().toUpperCase();
    const parsedLeverage =
      typeof leverage === "number" ? leverage : Number(leverage);

    if (
      supportedSymbols.has(normalizedSymbol as HyperliquidSymbol) &&
      Number.isFinite(parsedLeverage) &&
      parsedLeverage > 0
    ) {
      storedLeverageBySymbol[normalizedSymbol as HyperliquidSymbol] =
        Math.round(parsedLeverage);
    }

    return storedLeverageBySymbol;
  }, {});
}

