  function subscribeToMagicTradeTargetPrice(symbol: HyperliquidSymbol) {
    return new Promise<number | null>((resolve) => {
      const coin = getHyperliquidCoinFromMagicTradeSymbol(symbol);
      let websocket: WebSocket | null = null;
      let settled = false;
      let timeoutId: number | null = null;

      const settle = (price: number | null) => {
        if (settled) {
          return;
        }

        settled = true;

        if (timeoutId !== null) {
          window.clearTimeout(timeoutId);
        }

        websocket?.close();
        resolve(price);
      };

      try {
        websocket = new WebSocket(MAGIC_TRADE_HYPERLIQUID_WS_URL);
        timeoutId = window.setTimeout(() => settle(null), 5_000);

        websocket.addEventListener("open", () => {
          websocket?.send(
            JSON.stringify({
              method: "subscribe",
              subscription: {
                coin,
                type: "activeAssetCtx",
              },
            }),
          );
        });

        websocket.addEventListener("message", (event) => {
          try {
            const payload = JSON.parse(event.data as string) as unknown;

            if (
              !isMagicTradeWsActiveAssetCtxMessage(payload) ||
              payload.data.coin !== coin
            ) {
              return;
            }

            const price = Number(payload.data.ctx?.markPx);

            if (Number.isFinite(price) && price > 0) {
              settle(price);
            }
          } catch {
            // Wait for the next payload until the timeout expires.
          }
        });

        websocket.addEventListener("error", () => settle(null));
        websocket.addEventListener("close", () => settle(null));
      } catch {
        settle(null);
      }
    });
  }

  async function fetchMagicTradeLatestClose(symbol: HyperliquidSymbol) {
    try {
      const response = await fetch(
        `/api/chart?symbol=${encodeURIComponent(symbol)}&interval=1m`,
        { cache: "no-store" },
      );

      if (!response.ok) {
        return null;
      }

      const payload = (await response.json()) as unknown;
      const candles = Array.isArray(payload) ? payload : [];
      const latestCandle = candles.at(-1) as { close?: unknown } | undefined;
      const close = Number(latestCandle?.close);

      return Number.isFinite(close) && close > 0 ? close : null;
    } catch {
      return null;
    }
  }
