  function handleSoulRecommendationIgnore(recommendationId: string) {
    const recommendation = avatarSoulRecommendations.find(
      (item) => item.id === recommendationId,
    );

    if (!recommendation) {
      showToast("Soul recommendation ignored.", 700, "neutral");
      return;
    }

    const nextCount = recommendation.dismissalCount ?? 0;
    setSoulMemory((currentMemory) =>
      recordDismissedSoulRecommendation(
        currentMemory,
        recommendation.id,
        new Date().toISOString(),
        recommendation.type as SoulRecommendationType,
      ),
    );
    showToast(
      nextCount + 1 >= 3
        ? "Soul warning ignored again. Frequency control unlocked."
        : `Soul warning ignored (${nextCount + 1}/3).`,
      900,
      "neutral",
    );
  }

  function handleSoulRecommendationReviewRule(recommendationId: string) {
    const recommendation = avatarSoulRecommendations.find(
      (item) => item.id === recommendationId,
    );
    showToast(
      recommendation
        ? `${recommendation.title} review is staged for a later flow.`
        : "Rule review is staged for a later flow.",
      900,
      "neutral",
    );
  }

  function handleSoulRecommendationSnooze(recommendationId: string) {
    setSoulRecommendationActionState((currentState) => ({
      ...currentState,
      [recommendationId]: "snoozed",
    }));
    showToast("Soul recommendation snoozed for this session.", 700, "neutral");
  }

  function handleSoulRecommendationShowLess(recommendationId: string) {
    const recommendation = avatarSoulRecommendations.find(
      (item) => item.id === recommendationId,
    );

    if (!recommendation) {
      return;
    }

    setSoulMemory((currentMemory) =>
      recordSoulRecommendationReducedFrequency(
        currentMemory,
        recommendation.type as SoulRecommendationType,
        new Date().toISOString(),
      ),
    );
    showToast("This Soul warning type will appear less often.", 900, "neutral");
  }

