    tagAlongBuilderValidationMessages.length === 0 &&
    Boolean(tagAlongBuilderPreviewRule);
  const magicTradeArmReady =
    tagAlongComposerReady && magicTradeComposerStage === "review";
  const tagAlongComposerSourcePrice = tagAlongRuleBuilderDraft?.sourceSymbol
    ? (marketPrices[tagAlongRuleBuilderDraft.sourceSymbol] ??
      currentPriceBySymbolRef.current[tagAlongRuleBuilderDraft.sourceSymbol] ??
      null)
    : null;
  useEffect(() => {
    const sourceSymbol = tagAlongRuleBuilderDraft?.sourceSymbol as
      | HyperliquidSymbol
      | undefined;

    if (!sourceSymbol || tagAlongComposerSourcePrice !== null) {
      return;
    }

    const abortController = new AbortController();
    let isCurrentRequest = true;

    fetch(`/api/market-stats?symbol=${encodeURIComponent(sourceSymbol)}`, {
      signal: abortController.signal,
    })
      .then(async (response) => {
        if (!response.ok) {
          return null;
        }

        return (await response.json()) as HyperliquidMarketStats;
      })
      .then((marketStats) => {
        if (!isCurrentRequest || !marketStats) {
          return;
        }

        const nextPrice =
          marketStats.markPrice ??
          marketStats.oraclePrice ??
          marketStats.previousDayPrice ??
          null;

        if (
          nextPrice === null ||
          !Number.isFinite(nextPrice) ||
          nextPrice <= 0
        ) {
          return;
        }

        currentPriceBySymbolRef.current[sourceSymbol] = nextPrice;
        currentPriceUpdatedAtBySymbolRef.current[sourceSymbol] = Date.now();
        setMarketPrices((currentPrices) =>
          currentPrices[sourceSymbol] === nextPrice
            ? currentPrices
            : {
                ...currentPrices,
                [sourceSymbol]: nextPrice,
              },
        );
      })
      .catch((error: unknown) => {
        if (error instanceof DOMException && error.name === "AbortError") {
          return;
        }
      });

    return () => {
      isCurrentRequest = false;
      abortController.abort();
    };
  }, [tagAlongComposerSourcePrice, tagAlongRuleBuilderDraft?.sourceSymbol]);
  const magicTradeConditionRoot =
    magicTradeEventRoot ??
    (tagAlongRuleBuilderDraft
      ? getMagicTradeConditionRoot(tagAlongRuleBuilderDraft.sourceConditionType)
      : null);
  const magicTradeConditionDirection =
    tagAlongRuleBuilderDraft?.sourceConditionType ===
      "price-crosses-above-level" ||
    tagAlongRuleBuilderDraft?.sourceConditionType ===
      "candle-closes-above-level"
      ? "above"
      : tagAlongRuleBuilderDraft?.sourceConditionType ===
            "price-crosses-below-level" ||
          tagAlongRuleBuilderDraft?.sourceConditionType ===
            "candle-closes-below-level"
        ? "below"
        : "";
  const magicTradeSentenceTokens = tagAlongRuleBuilderDraft
