  useEffect(() => {
    if (!hasHydratedStorage || liveExchangePositions.length === 0) {
      return;
    }

    liveExchangePositions.forEach((position) => {
      if (
        !Number.isFinite(position.entryPrice) ||
        position.entryPrice <= 0 ||
        !Number.isFinite(position.size) ||
        position.size <= 0
      ) {
        return;
      }

      if (hasMatchingPositionOpenHistory(position)) {
        return;
      }

      const historyKey = getLivePositionHistoryKey(position);

      if (recoveredLivePositionHistoryKeysRef.current.has(historyKey)) {
        return;
      }

      recoveredLivePositionHistoryKeysRef.current.add(historyKey);
      const relatedLogs = appendSessionLogEntries([
        {
          category: "positions",
          description:
            "Position opened on Hyperliquid and recovered from live exchange state.",
          direction: position.direction,
          eventType: "position-opened",
          metadata: {
            recoveredFrom: "live-position-sync",
            syncStatus: position.syncStatus ?? "exchange",
          },
          pnl: null,
          price: position.entryPrice,
          size: position.size,
          source: "Live Position Sync",
          symbol: position.symbol,
        },
      ]);

      if (
        !journalEntriesRef.current.some(
          (entry) =>
            entry.status === "open" &&
            entry.symbol === position.symbol &&
            entry.direction === position.direction,
        )
      ) {
        createJournalEntryFromTrade({
          ...getJournalEntryClassification({ triggerSource: "market-manual" }),
          direction: position.direction,
          entryPrice: position.entryPrice,
          metadata: {
            recoveredFrom: "live-position-sync",
            syncStatus: position.syncStatus ?? "exchange",
          },
          orderId: null,
          relatedSessionLogIds: relatedLogs.map((entry) => entry.id),
          size: position.size,
          symbol: position.symbol,
        });
      }
    });
  }, [hasHydratedStorage, liveExchangePositions, sessionLogEntries]);

