  useEffect(() => {
    const abortController = new AbortController();

    async function refreshMarketMetadata() {
      try {
        const response = await fetch("/api/market-metadata", {
          cache: "no-store",
          signal: abortController.signal,
        });

        if (!response.ok) {
          return;
        }

        const payload = (await response.json()) as HyperliquidMarketMetadata[];

        if (abortController.signal.aborted) {
          return;
        }

        const portalMetadata =
          payload.length > 0
            ? getPortalMarketMetadata(payload)
            : FALLBACK_MARKET_METADATA;

        setMarketMetadataList(portalMetadata);
        setMarketMetadataBySymbol(
          portalMetadata.reduce<
            Partial<Record<PortalChartSymbol, PortalMarketMetadata>>
          >(
            (metadataBySymbol, metadata) => ({
              ...metadataBySymbol,
              [metadata.symbol]: metadata,
            }),
            {},
          ),
        );
      } catch (error) {
        if (!abortController.signal.aborted) {
          console.warn(
            "[portal] unable to refresh Hyperliquid market metadata",
            error,
          );
        }
      }
    }

    void refreshMarketMetadata();

    return () => {
      abortController.abort();
    };
  }, []);

