  function hasRecentExecutionForSymbol(symbol: HyperliquidSymbol) {
    const latestExecutionSummary = latestExecutionSummaryRef.current;

    return (
      latestExecutionSummary?.symbol === symbol &&
      Date.now() - latestExecutionSummary.timestamp <
        EXECUTION_POSITION_RECONCILIATION_GRACE_MS
    );
  }

  function mergeConfirmedExecutionPositions(
    nextPositions: LiveExchangePosition[],
  ) {
    const exchangeSymbols = new Set(
      nextPositions.map((position) => position.symbol),
    );
    const confirmedPositions = liveExchangePositionsRef.current.filter(
      (position) =>
        position.syncStatus === "confirmed-execution" &&
        !exchangeSymbols.has(position.symbol) &&
        hasRecentExecutionForSymbol(position.symbol),
    );

    return [...nextPositions, ...confirmedPositions];
  }

  function applyExchangePositions(nextPositions: LiveExchangePosition[]) {
    const mergedPositions = mergeConfirmedExecutionPositions(nextPositions);
    liveExchangePositionsRef.current = mergedPositions;
    setLiveExchangePositions(mergedPositions);
    reconcileActivePositionFromExchangePositions(mergedPositions);
  }

  function upsertConfirmedFillPosition(input: {
    actualFilledSize: number;
    direction: TradeDirection;
    entryOrderId: number | null;
    executionId: string;
    fillPrice: number;
    finalResult: "success" | "filled" | string;
    intendedSize: number;
    normalizedSize: number;
    symbol: HyperliquidSymbol;
    timestamp: number;
  }) {
    if (input.finalResult !== "success" && input.finalResult !== "filled") {
      return;
    }

    const confirmedSummary: ExecutionSummary = {
      actualFilledSize: input.actualFilledSize,
      direction: input.direction,
      entryOrder: {
        executionId: input.executionId,
        id: input.entryOrderId,
        status: "filled",
      },
      executionId: input.executionId,
      fillPrice: input.fillPrice,
      finalPositionState: null,
      finalResult: "success",
      intendedSize: input.intendedSize,
      normalizedSize: input.normalizedSize,
      symbol: input.symbol,
      timestamp: input.timestamp,
    };
    const confirmedPosition = buildConfirmedExecutionPosition(confirmedSummary);

    if (!confirmedPosition) {
      return;
    }

    latestExecutionSummaryRef.current = confirmedSummary;
    setLiveExchangePositions((currentPositions) => [
      confirmedPosition,
      ...currentPositions.filter(
        (position) => position.symbol !== confirmedPosition.symbol,
      ),
    ]);
  }

  function upsertConfirmedExecutionPosition(summary: ExecutionSummary) {
    upsertConfirmedFillPosition({
      actualFilledSize: summary.actualFilledSize,
      direction: summary.direction,
      entryOrderId: summary.entryOrder.id,
      executionId: summary.executionId,
      fillPrice: summary.fillPrice,
      finalResult: summary.finalResult,
      intendedSize: summary.intendedSize,
      normalizedSize: summary.normalizedSize,
      symbol: summary.symbol,
      timestamp: summary.timestamp,
    });
  }

  function clearRecentExecutionForSymbol(symbol: HyperliquidSymbol) {
    if (latestExecutionSummaryRef.current?.symbol === symbol) {
      latestExecutionSummaryRef.current = null;
    }
  }

  function reconcileActivePositionFromExchangePositions(
    nextPositions: LiveExchangePosition[],
  ) {
    const currentActiveSymbol = activeSymbolRef.current;
    const activeSymbolPosition = nextPositions.find(
      (position) => position.symbol === currentActiveSymbol,
    );

    if (!activeSymbolPosition) {
      if (
        hasRecentExecutionForSymbol(currentActiveSymbol as HyperliquidSymbol)
      ) {
        return;
      }

      setActivePosition((currentPosition) =>
        currentPosition?.symbol === currentActiveSymbol
          ? null
          : currentPosition,
      );
      setActiveTradePlan((currentTradePlan) =>
        currentTradePlan?.symbol === currentActiveSymbol
          ? null
          : currentTradePlan,
      );
      return;
    }

    setActivePosition((currentPosition) => {
      if (currentPosition?.symbol === activeSymbolPosition.symbol) {
        return {
          ...currentPosition,
          direction: activeSymbolPosition.direction,
          entry: activeSymbolPosition.entryPrice,
          size: activeSymbolPosition.size,
        };
      }

      const latestExecutionSummary = latestExecutionSummaryRef.current;
      const matchingExecutionSummary =
        latestExecutionSummary?.symbol === activeSymbolPosition.symbol &&
        latestExecutionSummary.direction === activeSymbolPosition.direction
          ? latestExecutionSummary
          : null;
      const executionId =
        matchingExecutionSummary?.executionId ??
        `exchange-live-${activeSymbolPosition.symbol}`;

      return {
        createdAt: matchingExecutionSummary
          ? new Date(matchingExecutionSummary.timestamp).toISOString()
          : new Date().toISOString(),
        direction: activeSymbolPosition.direction,
        entry: activeSymbolPosition.entryPrice,
        entryOrderId: matchingExecutionSummary?.entryOrder.id ?? null,
        executionId,
        id: `${activeSymbolPosition.symbol}-position-${executionId}`,
        size: activeSymbolPosition.size,
        symbol: activeSymbolPosition.symbol,
      };
    });
  }

