  useEffect(() => {
    let cancelled = false;
    let timeoutId: number | null = null;

    function getPollIntervalMs() {
      if (hasLiveOpenPosition) {
        return document.visibilityState === "visible"
          ? LIVE_POSITION_POLL_VISIBLE_MS
          : LIVE_POSITION_POLL_HIDDEN_MS;
      }

      return document.visibilityState === "visible"
        ? LIVE_STATE_POLL_VISIBLE_MS
        : LIVE_STATE_POLL_HIDDEN_MS;
    }

    function clearScheduledRefresh() {
      if (timeoutId !== null) {
        window.clearTimeout(timeoutId);
        timeoutId = null;
      }
    }

    function scheduleNextRefresh(delay = getPollIntervalMs()) {
      clearScheduledRefresh();

      timeoutId = window.setTimeout(() => {
        void refreshCriticalLiveState({
          force: true,
          reason: "background",
        }).finally(() => {
          if (!cancelled) {
            scheduleNextRefresh();
          }
        });
      }, delay);
    }

    function handleVisibilityChange() {
      if (cancelled) {
        return;
      }

      if (document.visibilityState === "visible") {
        void refreshCriticalLiveState({ reason: "background" }).finally(() => {
          if (!cancelled) {
            scheduleNextRefresh();
          }
        });
        return;
      }

      scheduleNextRefresh();
    }

    void refreshCriticalLiveState({
      force: true,
      reason: "background",
    }).finally(() => {
      if (!cancelled) {
        scheduleNextRefresh();
      }
    });

    document.addEventListener("visibilitychange", handleVisibilityChange);

    return () => {
      cancelled = true;
      clearScheduledRefresh();
      document.removeEventListener("visibilitychange", handleVisibilityChange);
    };
  }, [hasLiveOpenPosition]);

