  useEffect(() => {
    const currentPendingOrders = pendingLimitOrdersRef.current;

    if (currentPendingOrders.length === 0) {
      return;
    }

    const nextPendingOrders: PendingLimitOrder[] = [];
    const closedOrders: PendingLimitOrder[] = [];
    let filledOrder: PendingLimitOrder | null = null;
    let filledPosition: LiveExchangePosition | null = null;
    const claimedLivePendingOrderIds = new Set<number>();

    for (const pendingOrder of currentPendingOrders) {
      if (
        pendingOrder.status === "canceling" ||
        pendingOrder.status === "updating"
      ) {
        nextPendingOrders.push(pendingOrder);
        continue;
      }

      let matchingLivePendingOrder =
        livePendingOrders.find(
          (order) =>
            order.orderId === pendingOrder.orderId &&
            !claimedLivePendingOrderIds.has(order.orderId),
        ) ?? null;

      if (
        !matchingLivePendingOrder &&
        (pendingOrder.source === "mid-zone" ||
          pendingOrder.source === "order-zone")
      ) {
        matchingLivePendingOrder =
          livePendingOrders.find(
            (order) =>
              !claimedLivePendingOrderIds.has(order.orderId) &&
              order.symbol === pendingOrder.symbol &&
              order.direction === pendingOrder.direction &&
              Math.abs(order.price - pendingOrder.normalizedPrice) < 0.01 &&
              Math.abs(order.size - pendingOrder.normalizedSize) < 1e-9,
          ) ?? null;
      }

      if (matchingLivePendingOrder) {
        claimedLivePendingOrderIds.add(matchingLivePendingOrder.orderId);
        nextPendingOrders.push({
          ...pendingOrder,
          normalizedPrice: matchingLivePendingOrder.price,
          normalizedSize: matchingLivePendingOrder.size,
          orderId: matchingLivePendingOrder.orderId,
          status: "live",
        });
        continue;
      }

      const matchingLivePosition = liveExchangePositions.find(
        (position) =>
          position.symbol === pendingOrder.symbol &&
          position.direction === pendingOrder.direction,
      );

      if (!filledOrder && matchingLivePosition) {
        filledOrder = pendingOrder;
        filledPosition = matchingLivePosition;
        continue;
      }

      const pendingOrderCreatedAt = Date.parse(pendingOrder.createdAt);

      if (
        Number.isFinite(pendingOrderCreatedAt) &&
        Date.now() - pendingOrderCreatedAt <
          PENDING_ORDER_RECONCILIATION_GRACE_MS
      ) {
        nextPendingOrders.push(pendingOrder);
        continue;
      }

      if (
        (pendingOrder.source === "mid-zone" ||
          pendingOrder.source === "order-zone") &&
        pendingOrder.parentZoneId &&
        chartZones.some((zone) => zone.id === pendingOrder.parentZoneId)
      ) {
        nextPendingOrders.push({
          ...pendingOrder,
          status: "live",
        });
        continue;
      }

      closedOrders.push(pendingOrder);
    }

    const didOrdersChange =
      nextPendingOrders.length !== currentPendingOrders.length ||
      nextPendingOrders.some((order, index) => {
        const previousOrder = currentPendingOrders[index];
        return (
          !previousOrder ||
          previousOrder.id !== order.id ||
          previousOrder.normalizedPrice !== order.normalizedPrice ||
          previousOrder.normalizedSize !== order.normalizedSize ||
          previousOrder.status !== order.status
        );
      });

    if (didOrdersChange) {
      setPendingLimitOrders(nextPendingOrders);
    }

    if (filledOrder && filledPosition) {
      const relatedLogs = appendSessionLogEntries([
        {
          category: "orders",
          description: `${filledOrder.direction === "long" ? "Limit Buy" : "Limit Sell"} filled from live pending order.`,
          direction: filledOrder.direction,
          eventType: "pending-order-filled",
          metadata: {
            orderId: filledOrder.orderId,
            placementId: filledOrder.placementId,
          },
          pnl: null,
          price: filledPosition.entryPrice,
          size: filledPosition.size,
          source: getPendingOrderSourceLabel(filledOrder.source),
          symbol: filledOrder.symbol,
        },
        {
          category: "positions",
          description: `Position opened from pending ${filledOrder.direction} fill.`,
          direction: filledPosition.direction,
          eventType: "position-opened",
          metadata: {
            orderId: filledOrder.orderId,
            placementId: filledOrder.placementId,
          },
          pnl: null,
          price: filledPosition.entryPrice,
          size: filledPosition.size,
          source: getPendingOrderSourceLabel(filledOrder.source),
          symbol: filledPosition.symbol,
        },
      ]);
      createOrUpdateJournalEntryForOrderFill({
        ...getJournalEntryClassification({ orderSource: filledOrder.source }),
        direction: filledPosition.direction,
        entryPrice: filledPosition.entryPrice,
        executionId: filledOrder.placementId,
        orderId: filledOrder.orderId,
        relatedSessionLogIds: relatedLogs.map((entry) => entry.id),
        size: filledPosition.size,
        symbol: filledPosition.symbol,
      });
      setActivePosition({
        createdAt: new Date().toISOString(),
        direction: filledPosition.direction,
        entry: filledPosition.entryPrice,
        entryOrderId: filledOrder.orderId,
        executionId: filledOrder.placementId,
        id: `${filledPosition.symbol}-position-${filledOrder.placementId}`,
        size: filledPosition.size,
        symbol: filledPosition.symbol,
      });
      setPendingLimitOrders((currentOrders) =>
        currentOrders.filter((order) => order.id !== filledOrder.id),
      );
      setActiveTradePlan(null);
      setDraftTradePlan(null);
      setSelectedObject((currentSelection) =>
        currentSelection?.type === "pending-order" &&
        currentSelection.id === filledOrder.id
          ? null
          : currentSelection,
      );
      setLimitPlacementDirection(null);
      void refreshPostMutationLiveState();
      showOrderToast(
        "filled",
        "Limit order filled",
        undefined,
        0,
        buildLimitOrderToastReceipt({
          direction: filledOrder.direction,
          price: filledPosition.entryPrice,
          size: filledPosition.size,
          symbol: filledPosition.symbol,
        }),
      );
    }

    if (closedOrders.length > 0) {
      setPendingLimitOrders((currentOrders) =>
        currentOrders.filter(
          (order) =>
            !closedOrders.some((closedOrder) => closedOrder.id === order.id),
        ),
      );
      setSelectedObject((currentSelection) =>
        currentSelection?.type === "pending-order" &&
        closedOrders.some(
          (closedOrder) => closedOrder.id === currentSelection.id,
        )
          ? null
          : currentSelection,
      );
      void refreshPostMutationLiveState();
      showOrderToast(
        "canceled",
        closedOrders.length === 1
          ? "Pending order closed"
          : "Pending orders closed",
      );
    }
  }, [liveExchangePositions, livePendingOrders]);

