  function parseCommandNumber(value: string) {
    const match = value.match(/-?\d[\d,]*(?:\.\d+)?/);

    if (!match) {
      return null;
    }

    const parsedValue = Number(match[0].replaceAll(",", ""));

    return Number.isFinite(parsedValue) ? parsedValue : null;
  }

  function normalizeCommandInput(value: string) {
    return value.trim().replace(/^(rr|tp|sl)(-?\d)/i, "$1 $2");
  }

  function formatRuleNumber(value: number) {
    if (Number.isInteger(value)) {
      return String(value);
    }

    return value.toFixed(2).replace(/\.?0+$/, "");
  }

  function formatCooldownRemaining(value: number) {
    if (!Number.isFinite(value) || value <= 0) {
      return "Ready";
    }

    const totalSeconds = Math.ceil(value / 1000);
    const minutes = Math.floor(totalSeconds / 60);
    const seconds = totalSeconds % 60;

    if (minutes <= 0) {
      return `${seconds}s`;
    }

    return `${minutes}m ${String(seconds).padStart(2, "0")}s`;
  }

  function formatUsd(value: number | null) {
    if (value === null || !Number.isFinite(value)) {
      return "--";
    }

    return new Intl.NumberFormat("en-US", {
      currency: "USD",
      maximumFractionDigits: 2,
      minimumFractionDigits: 2,
      style: "currency",
    }).format(value);
  }

  function formatTradeSizeInputValue(value: number, unit: "usdc" | "base") {
    if (!Number.isFinite(value) || value < 0) {
      return "";
    }

    return unit === "usdc" ? value.toFixed(2) : value.toFixed(6);
  }

  function formatCurrentPositionSize(value: number) {
    if (!Number.isFinite(value)) {
      return `-- ${activeBaseAssetLabel}`;
    }

    return `${Math.abs(value).toFixed(5)} ${activeBaseAssetLabel}`;
  }

  function formatAllocationPercent(value: number) {
    if (!Number.isFinite(value)) {
      return "--";
    }

    return String(Math.min(100, Math.max(0, Math.round(value))));
  }

  function formatPortalPrice(value: number | null) {
    if (value === null || !Number.isFinite(value)) {
      return "--";
    }

    return new Intl.NumberFormat("en-US", {
      maximumFractionDigits: value >= 100 ? 0 : 2,
      minimumFractionDigits: value >= 100 ? 0 : 2,
    }).format(value);
  }

  function formatTradeSlippage(value: number | null) {
    if (value === null || !Number.isFinite(value)) {
      return "--";
    }

    return `${value.toFixed(4)}%`;
  }

  function formatDiagnosisGeneratedAt(timestamp: string) {
    const parsedDate = new Date(timestamp);

    if (Number.isNaN(parsedDate.getTime())) {
      return "now";
    }

    return new Intl.DateTimeFormat("en-US", {
      day: "2-digit",
      hour: "2-digit",
      hour12: false,
      minute: "2-digit",
      month: "2-digit",
    }).format(parsedDate);
  }

  function formatDiagnosisConfidence(confidence: OperatorDiagnosisConfidence) {
    switch (confidence) {
      case "high":
        return "High";
      case "medium":
        return "Medium";
      case "low":
        return "Low";
    }
  }

  function getDiagnosisFindingShellClass(finding: DiagnosisFinding) {
    switch (finding.severity) {
      case "critical":
        return "border-red-300/20 bg-[linear-gradient(135deg,rgba(239,68,68,0.11),rgba(10,12,20,0.66))] shadow-[inset_0_1px_0_rgba(255,255,255,0.07),0_0_24px_rgba(239,68,68,0.08)]";
      case "warning":
        return "border-amber-300/18 bg-[linear-gradient(135deg,rgba(245,158,11,0.10),rgba(10,12,20,0.64))] shadow-[inset_0_1px_0_rgba(255,255,255,0.07),0_0_20px_rgba(245,158,11,0.07)]";
      case "positive":
        return "border-emerald-300/16 bg-[linear-gradient(135deg,rgba(34,197,94,0.085),rgba(10,12,20,0.62))] shadow-[inset_0_1px_0_rgba(255,255,255,0.07),0_0_18px_rgba(34,197,94,0.07)]";
      case "info":
        return "border-cyan-300/14 bg-[linear-gradient(135deg,rgba(34,211,238,0.075),rgba(10,12,20,0.62))] shadow-[inset_0_1px_0_rgba(255,255,255,0.07)]";
    }
  }

  function getDiagnosisFindingDotClass(finding: DiagnosisFinding) {
    switch (finding.severity) {
      case "critical":
        return "bg-red-300 shadow-[0_0_12px_rgba(239,68,68,0.45)]";
      case "warning":
        return "bg-amber-300 shadow-[0_0_12px_rgba(245,158,11,0.38)]";
      case "positive":
        return "bg-emerald-300 shadow-[0_0_12px_rgba(34,197,94,0.35)]";
      case "info":
        return "bg-cyan-300 shadow-[0_0_12px_rgba(34,211,238,0.34)]";
    }
  }

  function getDiagnosisConfidencePercent(confidence: OperatorDiagnosisConfidence) {
    switch (confidence) {
      case "high":
        return 86;
      case "medium":
        return 68;
      case "low":
        return 42;
    }
  }

  function getDiagnosisSeverityLabel(finding: DiagnosisFinding) {
    switch (finding.severity) {
      case "critical":
        return "Needs review";
      case "warning":
        return "Needs review";
      case "positive":
        return "Edge detected";
      case "info":
        return "Watch";
    }
  }

  function getNativeSessionCandidateToneClass(candidate: {
    confidence: string;
    severity: string;
  }) {
    if (candidate.severity === "critical") {
      return "border-red-300/[0.14] bg-[linear-gradient(135deg,rgba(239,68,68,0.095),rgba(255,255,255,0.018))]";
    }

    if (candidate.severity === "positive") {
      return "border-emerald-300/[0.12] bg-[linear-gradient(135deg,rgba(34,197,94,0.075),rgba(255,255,255,0.016))]";
    }

    if (candidate.confidence === "high") {
      return "border-amber-300/[0.13] bg-[linear-gradient(135deg,rgba(245,158,11,0.075),rgba(255,255,255,0.016))]";
    }

    return "border-white/[0.055] bg-white/[0.022]";
  }

  function getNativeSessionCandidateDotClass(candidate: {
    confidence: string;
    severity: string;
  }) {
    if (candidate.severity === "positive") {
      return "bg-emerald-300 shadow-[0_0_10px_rgba(34,197,94,0.32)]";
    }

    if (candidate.severity === "critical") {
      return "bg-red-300 shadow-[0_0_10px_rgba(239,68,68,0.34)]";
    }

    if (candidate.confidence === "high") {
      return "bg-amber-300 shadow-[0_0_10px_rgba(245,158,11,0.30)]";
    }

    return "bg-cyan-300 shadow-[0_0_10px_rgba(34,211,238,0.24)]";
  }

  function formatDiagnosisImpact(finding: DiagnosisFinding) {
    const impactParts = [
      typeof finding.impact.netPnl === "number"
        ? `Net ${formatUsd(finding.impact.netPnl)}`
        : null,
      typeof finding.impact.winRate === "number"
        ? `Win ${(finding.impact.winRate * 100).toFixed(0)}%`
        : null,
      typeof finding.impact.tradeCount === "number"
        ? `${finding.impact.tradeCount} evidence`
        : null,
      typeof finding.impact.avgRr === "number"
        ? `Avg R:R ${finding.impact.avgRr.toFixed(2)}`
        : null,
    ];

    return impactParts.filter(Boolean);
  }

  function formatDiagnosisRuleValue(rule: RecommendedDisciplineRule) {
    const entries = Object.entries(rule.proposedValue);

    if (entries.length === 0) {
      return "Review required";
    }

    return entries
      .map(([key, value]) => {
        const label = key.replace(/([A-Z])/g, " $1").toLowerCase();
        return `${label}: ${String(value)}`;
      })
      .join(" · ");
  }

  function getDiagnosisRuleSupportLabel(
    status: RecommendedDisciplineRuleSupportStatus | undefined,
  ) {
    switch (status?.status) {
      case "ready":
        return "ready";
      case "blocked":
        return "blocked by locked rule";
      case "unsupported":
      default:
        return "unsupported in v1";
    }
  }

  function getDiagnosisRuleSupportClass(
    status: RecommendedDisciplineRuleSupportStatus | undefined,
  ) {
    switch (status?.status) {
      case "ready":
        return "border-cyan-300/16 bg-cyan-300/[0.07] text-cyan-50/78";
      case "blocked":
        return "border-amber-300/18 bg-amber-300/[0.08] text-amber-50/78";
      case "unsupported":
      default:
        return "border-white/[0.06] bg-white/[0.03] text-white/38";
    }
  }

  function formatDiagnosisActivationCount(
    rules:
      | ActivatedDisciplineRule[]
      | SkippedDisciplineRule[]
      | BlockedDisciplineRule[],
    label: string,
  ) {
    const pluralLabel =
      label === "skipped"
        ? "skipped"
        : `${label}${rules.length === 1 ? "" : "s"}`;
    return `${rules.length} ${pluralLabel}`;
  }

  function formatEstimatedBaseSize(
    value: number,
    symbol: HyperliquidSymbol | string | null | undefined,
  ) {
    const baseAssetLabel =
      typeof symbol === "string" && symbol.trim().length > 0
        ? symbol
            .trim()
            .toUpperCase()
            .replace(/-USDC$/i, "-USD")
            .replace(/-USD$/i, "")
        : "UNKNOWN";

    if (!Number.isFinite(value) || value <= 0) {
      return `-- ${baseAssetLabel}`;
    }

    return `${value.toFixed(6)} ${baseAssetLabel}`;
  }

  function formatLimitOrderReceiptSize(value: number) {
    if (!Number.isFinite(value) || value <= 0) {
      return "--";
    }

    return new Intl.NumberFormat("en-US", {
      maximumFractionDigits: 6,
      minimumFractionDigits: 0,
    }).format(value);
  }

  function formatLimitOrderReceiptAsset(
    symbol: HyperliquidSymbol | string | null | undefined,
  ) {
    if (typeof symbol !== "string" || symbol.trim().length === 0) {
      return activeBaseAssetLabel;
    }

    return symbol
      .trim()
      .toUpperCase()
      .replace(/-USDC$/i, "-USD")
      .replace(/-USD$/i, "");
  }

  function buildLimitOrderToastReceipt(input: {
    direction: TradeDirection;
    price: number;
    size: number;
    symbol?: HyperliquidSymbol | string | null;
  }): ToastReceipt {
    const sideLabel = input.direction === "long" ? "Long" : "Short";
    const assetLabel = formatLimitOrderReceiptAsset(
      input.symbol ?? activeSymbol,
    );

    return {
      price: `@ ${formatChartPriceInput(input.price)}`,
      summary: `${sideLabel} ${formatLimitOrderReceiptSize(input.size)} ${assetLabel}`,
    };
  }

  function formatDisciplineRuleTypeLabel(ruleType: string | null | undefined) {
    switch (ruleType) {
      case "cooldown_after_loss":
        return "Cooldown After Loss";
      case "max_daily_loss":
        return "Max Daily Loss";
      case "max_trades_per_day":
        return "Max Trades Per Day";
      case "no_trade_zone":
        return "No-Trade Zone";
      case "blocked_time_window":
        return "Blocked Time Window";
      default:
        return "Discipline Rule";
    }
  }

  function formatUsdcAmount(value: number | null) {
    if (value === null || !Number.isFinite(value)) {
      return "-- USDC";
    }

    return `${value.toFixed(value % 1 === 0 ? 0 : 2)} USDC`;
  }

  function formatTradeDuration(
    startTimestamp: string,
    endTimestamp: string | null,
  ) {
    if (!endTimestamp) {
      return "Not tracked yet";
    }

    const start = new Date(startTimestamp).getTime();
    const end = new Date(endTimestamp).getTime();

    if (!Number.isFinite(start) || !Number.isFinite(end) || end <= start) {
      return "Not tracked yet";
    }

    const totalMinutes = Math.max(1, Math.round((end - start) / 60_000));

    if (totalMinutes < 60) {
      return `${totalMinutes}m`;
    }

    const hours = Math.floor(totalMinutes / 60);
    const minutes = totalMinutes % 60;

    if (minutes === 0) {
      return `${hours}h`;
    }

    return `${hours}h ${minutes}m`;
  }

  function getExecutionSizeDecimals(symbol: HyperliquidSymbol) {
    return EXECUTION_SIZE_DECIMALS_BY_SYMBOL[symbol] ?? 5;
  }

  function normalizeExecutionSize(size: number, symbol: HyperliquidSymbol) {
    if (!Number.isFinite(size) || size <= 0) {
      return 0;
    }

    const decimals = getExecutionSizeDecimals(symbol);
    const factor = 10 ** decimals;

    return Math.floor(size * factor) / factor;
  }

  function getMagicTradeMarginReservationSummary(
    options: { excludeRuleId?: string | null } = {},
  ) {
    return deriveMagicTradeMarginReservation({
      availableToTrade,
      availableToTradeBySide,
      excludeRuleId: options.excludeRuleId,
      rules: tagAlongRulesRef.current,
    });
  }

  function getAvailableToTradeForDirection(
    direction: TradeDirection,
    options: { excludeRuleId?: string | null } = {},
  ) {
    const reservationSummary = getMagicTradeMarginReservationSummary(options);
    const sideSpecificAvailableToTrade =
      reservationSummary.remainingAvailableToTradeBySide[direction];

    if (
      sideSpecificAvailableToTrade !== null &&
      Number.isFinite(sideSpecificAvailableToTrade)
    ) {
      return sideSpecificAvailableToTrade;
    }

    if (
      reservationSummary.remainingAvailableToTrade !== null &&
      Number.isFinite(reservationSummary.remainingAvailableToTrade)
    ) {
      return reservationSummary.remainingAvailableToTrade;
    }

    return accountValue ?? 0;
  }

  function formatBlockedTimeWindowRange(
    rule: Pick<BlockedTimeWindowRule, "endTime" | "startTime">,
  ) {
    return `${rule.startTime}-${rule.endTime}`;
  }

  function updateDisciplineTracking(
    updater: (tracking: DisciplineTracking) => DisciplineTracking,
  ) {
    setDisciplineTracking((currentTracking) => {
      const nextTracking = getFreshDisciplineTracking(
        updater(
          getFreshDisciplineTracking(
            currentTracking,
            disciplineRulesRef.current,
          ),
        ),
        disciplineRulesRef.current,
      );
      disciplineTrackingRef.current = nextTracking;
      return nextTracking;
    });
  }

  function registerTradesPlaced(count: number) {
    if (!Number.isFinite(count) || count <= 0) {
      return;
    }

    updateDisciplineTracking((tracking) => ({
      ...tracking,
      tradesPlacedToday: tracking.tradesPlacedToday + Math.floor(count),
    }));
  }

  function recordRealizedPnl(realizedPnl: number | null) {
    if (realizedPnl === null || !Number.isFinite(realizedPnl)) {
      return;
    }

    updateDisciplineTracking((tracking) => ({
      ...tracking,
      lastLosingTradeAt:
        realizedPnl < 0 ? new Date().toISOString() : tracking.lastLosingTradeAt,
      realizedPnlToday: tracking.realizedPnlToday + realizedPnl,
    }));
  }

  function appendJournalMemoryEventsSafe(events: JournalMemoryEvent[]) {
    if (events.length === 0) {
      return;
    }

    setJournalMemoryEvents((currentEvents) => {
      const nextEvents = appendJournalMemoryEvents(currentEvents, events);
      return JSON.stringify(currentEvents) === JSON.stringify(nextEvents)
        ? currentEvents
        : nextEvents;
    });
  }

  function appendJournalMemoryEventsForSessionLogs(
    entries: SessionLogEntry[],
    journalEntriesSnapshot: JournalEntry[] = journalEntriesRef.current,
  ) {
    const activeTradeSymbols = liveExchangePositionsRef.current
      .filter((position) => Number.isFinite(position.size) && position.size > 0)
      .map((position) => position.symbol);
    const memoryJournalEntries = entries.some(
      (entry) =>
        entry.eventType === "discipline-rule-blocked" ||
        entry.eventType === "discipline-rule-edit-blocked" ||
        entry.eventType === "discipline-override-bond-posted",
    )
      ? filterJournalEntriesWithActiveTradeSymbols(
          journalEntriesSnapshot,
          activeTradeSymbols,
        )
      : journalEntriesSnapshot;

    appendJournalMemoryEventsSafe(
      entries.flatMap((entry) =>
        mapSessionLogEntryToJournalMemoryEvents(entry, memoryJournalEntries, {
          activeTradeSymbols,
        }),
      ),
    );
  }

  function appendSessionLogEntries(
    entries: Array<
      Omit<SessionLogEntry, "id" | "timestamp"> & { timestamp?: string }
    >,
  ) {
    if (entries.length === 0) {
      return [] as SessionLogEntry[];
    }

    try {
      const nextEntries = createSessionLogEntries(entries);

      setSessionLogEntries((currentEntries) =>
        prependSessionLogEntries(currentEntries, nextEntries),
      );
      appendJournalMemoryEventsForSessionLogs(nextEntries);
      return nextEntries;
    } catch (error) {
      console.warn("[portal] unable to append session log", error);
      return [] as SessionLogEntry[];
    }
  }

  function getLivePositionHistoryKey(position: LiveExchangePosition) {
    return [
      position.symbol,
      position.direction,
      Number.isFinite(position.entryPrice)
        ? position.entryPrice.toFixed(8)
        : "unknown-entry",
      Number.isFinite(position.size)
        ? position.size.toFixed(8)
        : "unknown-size",
    ].join(":");
  }

  function hasMatchingPositionOpenHistory(position: LiveExchangePosition) {
    return sessionLogEntries.some((entry) => {
      if (
        entry.eventType !== "position-opened" ||
        entry.symbol !== position.symbol ||
        entry.direction !== position.direction ||
        entry.price === null ||
        entry.size === null
      ) {
        return false;
      }

      const priceMatches =
        Math.abs(entry.price - position.entryPrice) <=
        Math.max(Math.abs(position.entryPrice) * 0.000001, 0.000001);
      const sizeMatches =
        Math.abs(entry.size - position.size) <=
        Math.max(Math.abs(position.size) * 0.000001, 0.000001);

      return priceMatches && sizeMatches;
    });
  }

  async function openJournalSnapshotDb() {
    if (typeof window === "undefined" || !("indexedDB" in window)) {
      return null;
    }

    return await new Promise<IDBDatabase | null>((resolve, reject) => {
      const request = window.indexedDB.open(
        JOURNAL_SNAPSHOT_DB_NAME,
        JOURNAL_SNAPSHOT_DB_VERSION,
      );

      request.onupgradeneeded = () => {
        const database = request.result;

        if (!database.objectStoreNames.contains(JOURNAL_SNAPSHOT_STORE_NAME)) {
          database.createObjectStore(JOURNAL_SNAPSHOT_STORE_NAME, {
            keyPath: "storageKey",
          });
        }
      };

      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  }

  async function storeJournalSnapshotBlob(
    storageKey: string,
    snapshot: JournalChartSnapshot,
  ) {
    const database = await openJournalSnapshotDb();

    if (!database) {
      return false;
    }

    try {
      await new Promise<void>((resolve, reject) => {
        const transaction = database.transaction(
          JOURNAL_SNAPSHOT_STORE_NAME,
          "readwrite",
        );
        const store = transaction.objectStore(JOURNAL_SNAPSHOT_STORE_NAME);
        store.put({
          fullBlob: snapshot.fullBlob,
          fullHeight: snapshot.fullHeight,
          fullWidth: snapshot.fullWidth,
          markerLabel: snapshot.marker?.label,
          markerPrice: snapshot.marker?.price,
          markerTone: snapshot.marker?.tone,
          markerYPercent: snapshot.marker?.yPercent ?? null,
          previewBlob: snapshot.previewBlob,
          previewHeight: snapshot.previewHeight,
          previewWidth: snapshot.previewWidth,
          storageKey,
          storedAt: new Date().toISOString(),
        });
        transaction.oncomplete = () => resolve();
        transaction.onerror = () => reject(transaction.error);
        transaction.onabort = () => reject(transaction.error);
      });

      return true;
    } finally {
      database.close();
    }
  }

  async function loadJournalSnapshotBlob(
    storageKey: string,
    variant: "full" | "preview" = "full",
  ) {
    const record = await loadJournalSnapshotRecord(storageKey);

    if (!record) {
      return null;
    }

    if (variant === "preview") {
      return record.previewBlob ?? record.blob ?? record.fullBlob ?? null;
    }

    return record.fullBlob ?? record.blob ?? null;
  }

  async function loadJournalSnapshotRecord(storageKey: string) {
    const database = await openJournalSnapshotDb();

    if (!database) {
      return null;
    }

    try {
      return await new Promise<JournalSnapshotStoreRecord | null>(
        (resolve, reject) => {
          const transaction = database.transaction(
            JOURNAL_SNAPSHOT_STORE_NAME,
            "readonly",
          );
          const store = transaction.objectStore(JOURNAL_SNAPSHOT_STORE_NAME);
          const request = store.get(storageKey) as IDBRequest<
            JournalSnapshotStoreRecord | undefined
          >;

          request.onsuccess = () => resolve(request.result ?? null);
          request.onerror = () => reject(request.error);
        },
      );
    } finally {
      database.close();
    }
  }

  function getJournalSnapshotMarkerFromRecord(
    record: JournalSnapshotStoreRecord,
  ): HydratedJournalSnapshotMarker | null {
    if (
      typeof record.markerLabel !== "string" ||
      typeof record.markerPrice !== "number" ||
      !Number.isFinite(record.markerPrice) ||
      (record.markerTone !== "entry" && record.markerTone !== "exit")
    ) {
      return null;
    }

    return {
      label: record.markerLabel,
      price: record.markerPrice,
      tone: record.markerTone,
      yPercent:
        typeof record.markerYPercent === "number" &&
        Number.isFinite(record.markerYPercent)
          ? record.markerYPercent
          : null,
    };
  }

  async function deleteJournalSnapshotBlob(storageKey: string) {
    const database = await openJournalSnapshotDb();

    if (!database) {
      return;
    }

    try {
      await new Promise<void>((resolve, reject) => {
        const transaction = database.transaction(
          JOURNAL_SNAPSHOT_STORE_NAME,
          "readwrite",
        );
        const store = transaction.objectStore(JOURNAL_SNAPSHOT_STORE_NAME);
        store.delete(storageKey);
        transaction.oncomplete = () => resolve();
        transaction.onerror = () => reject(transaction.error);
        transaction.onabort = () => reject(transaction.error);
      });
    } finally {
      database.close();
    }
  }

  function warnJournalSnapshotLoadIssue(
    reason: "hydrate-failed" | "missing-frame-blob",
    details: {
      error?: unknown;
      event: JournalReplayFrameEvent;
      frameId: string;
      journalEntryId: string;
      storageKey: string;
    },
  ) {
    const warningKey = `${reason}:${details.frameId}:${details.storageKey}`;

    if (journalSnapshotWarningKeysRef.current.has(warningKey)) {
      return;
    }

    journalSnapshotWarningKeysRef.current.add(warningKey);
    console.warn("[portal] journal snapshot load issue", {
      error: details.error,
      eventType: details.event,
      frameId: details.frameId,
      journalEntryId: details.journalEntryId,
      reason,
      storageKey: details.storageKey,
    });
  }

  function logJournalReplayEvent(
    message: string,
    details: Record<string, unknown> = {},
  ) {
    console.debug("[portal] journal replay", {
      ...details,
      message,
    });
  }

  function appendReplayFrameToJournalEntry(
    symbol: string,
    event: JournalReplayFrameEvent,
    details: {
      pnl?: number | null;
      price?: number | null;
      size?: number | null;
      status?: JournalReplayFramePlan["status"];
      storageKey?: string | null;
    } = {},
  ) {
    const latestEntry = journalEntriesRef.current.find(
      (entry) => entry.symbol === symbol && entry.status === "open",
    );

    if (!latestEntry) {
      return null;
    }

    const frame = createJournalReplayFrame({
      event,
      journalEntryId: latestEntry.id,
      pnl: details.pnl,
      price: details.price,
      size: details.size,
      status: details.status,
      storageKey: details.storageKey,
    });

    updateJournalEntryById(
      latestEntry.id,
      (entry) => appendJournalReplayFramePlanToEntry(entry, frame).entry,
    );

    return frame;
  }

  function updateReplayFrameForJournalEntry(
    journalEntryId: string,
    frameId: string,
    updater: (frame: JournalReplayFramePlan) => JournalReplayFramePlan,
  ) {
    updateJournalEntryById(journalEntryId, (entry) =>
      updateJournalReplayFrameForEntry(entry, frameId, updater),
    );
  }

  function captureReplayFrameForSymbol(
    symbol: string,
    event: JournalReplayFrameEvent,
    details: {
      delayMs?: number;
      maxAttempts?: number;
      pnl?: number | null;
      price?: number | null;
      retryDelayMs?: number;
      size?: number | null;
    } = {},
  ) {
    const frame = appendReplayFrameToJournalEntry(symbol, event, {
      pnl: details.pnl,
      price: details.price,
      size: details.size,
    });

    if (!frame) {
      return null;
    }

    logJournalReplayEvent("frame added to live buffer", {
      eventType: event,
      frameId: frame.id,
      journalEntryId: frame.journalEntryId,
      symbol,
    });

    scheduleJournalSnapshotCapture({
      delayMs: details.delayMs,
      frameId: frame.id,
      journalEntryId: frame.journalEntryId,
      maxAttempts: details.maxAttempts ?? 5,
      pnl: details.pnl,
      price: details.price,
      retryDelayMs: details.retryDelayMs ?? 320,
      size: details.size,
    });

    return frame;
  }

  function appendExitReplayFrameToJournalEntry(
    journalEntryId: string,
    details: {
      pnl?: number | null;
      price?: number | null;
      size?: number | null;
    },
  ) {
    const exitFrame = createJournalReplayFrame({
      event: "exit",
      journalEntryId,
      pnl: details.pnl,
      price: details.price,
      size: details.size,
    });

    updateJournalEntryById(
      journalEntryId,
      (entry) => appendJournalReplayFramePlanToEntry(entry, exitFrame).entry,
    );

    scheduleJournalSnapshotCapture({
      delayMs: 120,
      frameId: exitFrame.id,
      journalEntryId,
      maxAttempts: 8,
      pnl: details.pnl,
      price: details.price,
      retryDelayMs: 360,
      size: details.size,
    });
  }

  async function finalizeJournalReplayTimeline(journalEntryId: string) {
    const entry = journalEntriesRef.current.find(
      (candidateEntry) => candidateEntry.id === journalEntryId,
    );

    if (!entry || entry.status !== "closed") {
      return;
    }

    const frames = [...entry.replayMetadata.frames].sort(
      (leftFrame, rightFrame) =>
        leftFrame.capturedAt.localeCompare(rightFrame.capturedAt),
    );
    logJournalReplayEvent("final downsampling started", {
      inputFrameCount: frames.length,
      journalEntryId,
      periodicFrameCount: frames.filter((frame) => frame.event === "periodic")
        .length,
    });

    if (frames.length === 0) {
      updateJournalEntryById(journalEntryId, (currentEntry) => ({
        ...currentEntry,
        replayMetadata: {
          ...currentEntry.replayMetadata,
          rawFrameCount: 0,
          replayStatus: "unavailable",
          savedFrameCount: 0,
        },
      }));
      return;
    }

    const durationMinutes = Math.max(
      0,
      (Date.parse(frames.at(-1)?.capturedAt ?? entry.updatedAt) -
        Date.parse(entry.timestamp)) /
        60_000,
    );
    const targetFrameCount = Math.min(
      entry.replayMetadata.finalTimelineMaxFrames,
      getReplayTargetFrameCount(durationMinutes),
    );
    const mandatoryFrames = frames.filter(
      (frame) => frame.event === "entry" || frame.event === "exit",
    );
    const keyFrames = frames.filter(
      (frame) =>
        frame.event !== "entry" &&
        frame.event !== "exit" &&
        frame.event !== "periodic",
    );
    const periodicFrames = frames.filter((frame) => frame.event === "periodic");
    const selectedFrameIds = new Set<string>();
    const selectedFrames: JournalReplayFramePlan[] = [];

    const pushFrame = (frame: JournalReplayFramePlan | null) => {
      if (
        !frame ||
        selectedFrameIds.has(frame.id) ||
        selectedFrames.length >= targetFrameCount
      ) {
        return;
      }

      selectedFrameIds.add(frame.id);
      selectedFrames.push(frame);
    };

    mandatoryFrames.forEach((frame) => pushFrame(frame));
    keyFrames.forEach((frame) => pushFrame(frame));

    const remainingSlotCount = Math.max(
      0,
      targetFrameCount - selectedFrames.length,
    );

    if (remainingSlotCount > 0 && periodicFrames.length > 0) {
      const periodicCount = Math.min(remainingSlotCount, periodicFrames.length);

      for (let index = 0; index < periodicCount; index += 1) {
        const periodicFrameIndex =
          periodicCount === 1
            ? Math.floor((periodicFrames.length - 1) / 2)
            : Math.round(
                (index * (periodicFrames.length - 1)) /
                  Math.max(1, periodicCount - 1),
              );
        pushFrame(periodicFrames[periodicFrameIndex] ?? null);
      }
    }

    frames.forEach((frame) => pushFrame(frame));

    const finalizedFrames = [...selectedFrames].sort((leftFrame, rightFrame) =>
      leftFrame.capturedAt.localeCompare(rightFrame.capturedAt),
    );
    const finalizedFrameIdSet = new Set(
      finalizedFrames.map((frame) => frame.id),
    );

    await Promise.all(
      frames
        .filter(
          (frame) =>
            !finalizedFrameIdSet.has(frame.id) &&
            typeof frame.storageKey === "string",
        )
        .map(async (frame) => {
          try {
            await deleteJournalSnapshotBlob(frame.storageKey as string);
          } catch (error) {
            console.warn("[portal] unable to prune replay snapshot frame", {
              error,
              frameId: frame.id,
              journalEntryId,
              storageKey: frame.storageKey,
            });
          }
        }),
    );

    updateJournalEntryById(journalEntryId, (currentEntry) => ({
      ...currentEntry,
      replayMetadata: {
        ...currentEntry.replayMetadata,
        frames: finalizedFrames,
        rawFrameCount: frames.length,
        replayStatus: finalizedFrames.some(
          (frame) => frame.status === "captured",
        )
          ? "finalized"
          : "unavailable",
        savedFrameCount: finalizedFrames.length,
      },
    }));
    logJournalReplayEvent("final downsampling completed", {
      inputFrameCount: frames.length,
      journalEntryId,
      periodicFrameCount: frames.filter((frame) => frame.event === "periodic")
        .length,
      savedFrameCount: finalizedFrames.length,
      savedPeriodicFrameCount: finalizedFrames.filter(
        (frame) => frame.event === "periodic",
      ).length,
    });
  }

  function getActiveDisciplineRuleSnapshot() {
    const rules = disciplineRulesRef.current;
    const nextRules: string[] = [];

    if (rules.maxDailyLoss !== null) {
      nextRules.push(`Max Daily Loss ${formatUsd(-rules.maxDailyLoss)}`);
    }

    if (rules.maxTradesPerDay !== null) {
      nextRules.push(`Max Trades ${formatRuleNumber(rules.maxTradesPerDay)}`);
    }

    if (rules.cooldownAfterLossMinutes !== null) {
      nextRules.push(
        `Cooldown ${formatRuleNumber(rules.cooldownAfterLossMinutes)}m`,
      );
    }

    (rules.blockedTimeWindows ?? []).forEach((rule) => {
      if (rule.enabled) {
        nextRules.push(`Blocked Window ${formatBlockedTimeWindowRange(rule)}`);
      }
    });

    return nextRules;
  }

  function createJournalEntryFromTrade(
    details: Parameters<typeof buildOpenedJournalEntryCapture>[0],
  ) {
    const capture = buildOpenedJournalEntryCapture(details, {
      activeChartTimeframe,
      captureIntervalTargetSeconds: JOURNAL_REPLAY_CAPTURE_INTERVAL_SECONDS,
      disciplineRulesSnapshot: getActiveDisciplineRuleSnapshot(),
    });
    try {
      setJournalEntries((currentEntries) =>
        commitJournalEntriesRefUpdate(
          journalEntriesRef,
          currentEntries,
          (entries) =>
            [capture.entry, ...entries].slice(0, MAX_JOURNAL_ENTRIES),
        ),
      );
      appendJournalMemoryEventsSafe(capture.memoryEvents);
      scheduleJournalSnapshotCapture(capture.snapshotRequest);
    } catch (error) {
      console.warn("[portal] unable to create journal entry", error);
    }

    return capture.entry;
  }

  function createOrUpdateJournalEntryForOrderFill(
    details: Parameters<typeof createJournalEntryFromTrade>[0],
  ) {
    const activeEntry = resolveOpenJournalEntryForTradeFill(
      journalEntriesRef.current,
      details,
    );

    if (activeEntry) {
      updateLatestJournalEntryForOrderFilledTrade(details.symbol as string, {
        childOrderId: details.orderId,
        clientOrderId: details.clientOrderId,
        executionId: details.executionId,
        fillPrice: details.entryPrice,
        fillSize: details.size,
        orderId: details.orderId,
        orderZoneId: details.orderZoneId,
        relatedSessionLogIds: details.relatedSessionLogIds,
        timestamp: details.timestamp ?? new Date().toISOString(),
      });
      appendJournalMemoryEventsSafe([
        buildOrderFilledMemoryEventForActiveEntry(details, activeEntry),
      ]);
      return activeEntry;
    }

    return createJournalEntryFromTrade(details);
  }

  function capturePendingJournalSetup(setupTag: string) {
    const trimmedSetupTag = setupTag.trim();

    if (!pendingJournalSetupEntry || !trimmedSetupTag) {
      return;
    }

    const returnTab = journalSetupReturnTab ?? "trade";

    updateJournalEntryById(pendingJournalSetupEntry.id, (entry) => ({
      ...entry,
      isCustomSetupTag: !DEFAULT_JOURNAL_SETUP_TAGS.includes(
        trimmedSetupTag as (typeof DEFAULT_JOURNAL_SETUP_TAGS)[number],
      ),
      setupCapturedAt: new Date().toISOString(),
      setupStatus: "captured",
      setupTag: trimmedSetupTag,
      setupType: trimmedSetupTag,
    }));
    setRenderedJournalSetupEntry(pendingJournalSetupEntry);
    setJournalSetupGateMotionState("exit");
    setSelectedPendingSetupTag(trimmedSetupTag);
    setPendingJournalSetupEntryId(null);
    setHoveredPendingSetupTag(null);
    setShowCustomSetupTagInput(false);
    setCustomSetupTagDraft("");
    setJournalSetupReturnTab(null);
    setSelectedFooterTab(returnTab);

    if (returnTab === "trade") {
      setIsReviewWorkspaceExpanded(false);
      setTradeFooterSidePanel("command");
    }
  }

  function skipPendingJournalSetup() {
    if (!pendingJournalSetupEntry) {
      return;
    }

    const returnTab = journalSetupReturnTab ?? selectedFooterTab;

    updateJournalEntryById(pendingJournalSetupEntry.id, (entry) => ({
      ...entry,
      isCustomSetupTag: false,
      setupCapturedAt: new Date().toISOString(),
      setupStatus: "skipped",
      setupTag: null,
      setupType: "",
    }));
    setRenderedJournalSetupEntry(pendingJournalSetupEntry);
    setJournalSetupGateMotionState("exit");
    setSelectedPendingSetupTag(null);
    setPendingJournalSetupEntryId(null);
    setHoveredPendingSetupTag(null);
    setShowCustomSetupTagInput(false);
    setCustomSetupTagDraft("");
    setJournalSetupReturnTab(null);
    setSelectedFooterTab(returnTab);
  }

  function savePendingJournalSetup() {
    if (!selectedPendingSetupTag) {
      return;
    }

    capturePendingJournalSetup(selectedPendingSetupTag);
  }

