  async function handleBreakEven(symbol: HyperliquidSymbol) {
    const position = activePositionRef.current;
    const currentTradePlan = activeTradePlanRef.current;

    const breakEvenContext = resolveBreakEvenProtectionContext({
      activePosition: position,
      livePositions: liveExchangePositionsRef.current,
      symbol,
      tradePlan: currentTradePlan,
    });

    if (!breakEvenContext.ok) {
      showToast(breakEvenContext.message);
      return;
    }

    const previousTradePlan =
      currentTradePlan?.symbol === symbol ? currentTradePlan : null;
    const nextTradePlan: ChartTradePlan | null = previousTradePlan
      ? {
          ...previousTradePlan,
          entry: breakEvenContext.entryPrice,
          stop: breakEvenContext.stopPrice,
          target: breakEvenContext.targetPrice,
        }
      : null;

    if (nextTradePlan) {
      setActiveTradePlan(nextTradePlan);
    }

    try {
      await syncProtectionLevels(breakEvenContext.position, {
        stop: breakEvenContext.stopPrice,
        target: breakEvenContext.targetPrice,
      });
      appendSessionLogEntries([
        {
          category: "protection",
          description: "Break-even used and stop moved to entry.",
          direction: breakEvenContext.position.direction,
          eventType: "break-even-used",
          pnl: null,
          price: breakEvenContext.entryPrice,
          size: breakEvenContext.position.size,
          source: "Break Even",
          symbol: breakEvenContext.position.symbol,
        },
      ]);
      captureReplayFrameForSymbol(
        breakEvenContext.position.symbol,
        "break-even",
        {
          price: breakEvenContext.entryPrice,
          size: breakEvenContext.position.size,
        },
      );
      void refreshPostMutationLiveState();
      showToast("Protection updated — stop moved to entry", 0, "success");
    } catch (error) {
      if (nextTradePlan) {
        setActiveTradePlan(previousTradePlan);
      }
      showToast(
        formatProtectionErrorMessage(
          error instanceof Error
            ? error.message
            : "unable to update protective orders",
        ),
      );
    }
  }

  async function handleClosePosition(symbol: HyperliquidSymbol) {
    if (positionActionInFlightSymbol === symbol) {
      return;
    }

    const livePosition = liveExchangePositions.find(
      (position) => position.symbol === symbol,
    );

    if (!livePosition) {
      showToast("Close position failed — no live position exists");
      return;
    }

    setPositionActionInFlightSymbol(symbol);
    setExecutionStatusMessage("Closing position...");

    try {
      const response = await fetch("/api/close-position", {
        body: JSON.stringify({ symbol }),
        headers: {
          "Content-Type": "application/json",
        },
        method: "POST",
      });

      const payload = (await response.json()) as { error?: string };

      if (!response.ok) {
        showToast(
          formatExecutionErrorMessage(
            payload.error ?? "unable to close testnet position",
          ),
        );
        return;
      }

      clearRecentExecutionForSymbol(symbol);
      setActivePosition((currentPosition) =>
        currentPosition?.symbol === symbol ? null : currentPosition,
      );
      setActiveTradePlan((currentTradePlan) =>
        currentTradePlan?.symbol === symbol ? null : currentTradePlan,
      );
      setLiveExchangePositions((currentPositions) =>
        currentPositions.filter((position) => position.symbol !== symbol),
      );
      recordRealizedPnl(livePosition.pnlUsd);
      const relatedLogs = appendSessionLogEntries([
        {
          category: "positions",
          description: "Position closed on Hyperliquid testnet.",
          direction: livePosition.direction,
          eventType: "position-closed",
          pnl: livePosition.pnlUsd,
          price: livePosition.entryPrice,
          size: livePosition.size,
          source: "Close Position",
          symbol,
        },
      ]);
      const openJournalEntry = getLatestOpenJournalEntry(symbol);
      updateLatestJournalEntryForClosedTrade(symbol, {
        exitPrice: activeMarketPrice ?? livePosition.entryPrice,
        grossPnl: livePosition.pnlUsd ?? null,
        realizedPnl: livePosition.pnlUsd ?? null,
        relatedSessionLogIds: relatedLogs.map((log) => log.id),
        size: livePosition.size,
        timestamp: relatedLogs[0]?.timestamp ?? new Date().toISOString(),
      });
      if (openJournalEntry) {
        appendExitReplayFrameToJournalEntry(openJournalEntry.id, {
          pnl: livePosition.pnlUsd ?? null,
          price: activeMarketPrice ?? livePosition.entryPrice,
          size: livePosition.size,
        });
      }
      void refreshPostMutationLiveState();
      showOrderToast("filled", "Position closed");
    } catch {
      showOrderToast("rejected", "Close rejected", "Connection unavailable.");
    } finally {
      setPositionActionInFlightSymbol((currentSymbol) =>
        currentSymbol === symbol ? null : currentSymbol,
      );
      setExecutionStatusMessage(null);
    }
  }

  async function handleLimitClosePosition(
    symbol: HyperliquidSymbol,
    percent: number,
    price: number,
    priceSource: "current" | "chart" | "typed",
  ) {
    if (positionActionInFlightSymbol === symbol || isExecuting) {
      showOrderToast(
        "blocked",
        "Execution blocked",
        "Request already in progress.",
      );
      return;
    }

    const livePosition = liveExchangePositions.find(
      (position) => position.symbol === symbol,
    );

    if (
      !livePosition ||
      !Number.isFinite(livePosition.size) ||
      livePosition.size <= 0
    ) {
      showOrderToast(
        "blocked",
        "Limit close blocked",
        "No live position exists.",
      );
      setLimitClosePricePick(null);
      return;
    }

    const normalizedPercent = Math.min(100, Math.max(1, Math.round(percent)));
    const limitCloseSize = livePosition.size * (normalizedPercent / 100);
    const closeDirection = livePosition.direction === "long" ? "short" : "long";
    const placementGuard = evaluateLimitOrderPlacementGuard(
      { direction: closeDirection, reduceOnly: true },
      livePosition,
    );

    if (!placementGuard.allowed) {
      showToast(placementGuard.reason);
      setLimitClosePricePick(null);
      return;
    }

    if (!Number.isFinite(price) || price <= 0) {
      showOrderToast("blocked", "Limit close blocked", "Invalid price.");
      return;
    }

    if (!Number.isFinite(limitCloseSize) || limitCloseSize <= 0) {
      showOrderToast("blocked", "Limit close blocked", "Size is too small.");
      setLimitClosePricePick(null);
      return;
    }

    const placementId = `limit-close-${Date.now()}-${crypto.randomUUID()}`;
    setPositionActionInFlightSymbol(symbol);
    setExecutionStatusMessage("Confirming limit close");
    setLimitOrderRequestState("placing");
    setIsExecuting(true);

    try {
      const { ok, payload } = await requestLimitOrderPlacement(
        price,
        closeDirection,
        limitCloseSize,
        placementId,
        { reduceOnly: true, symbol },
      );

      if (!ok || !payload.summary) {
        if (
          showServerDisciplineBlockedPayload(payload, {
            direction: closeDirection,
            price,
            size: limitCloseSize,
            symbol,
          })
        ) {
          return;
        }

        showToast(
          formatExecutionErrorMessage(
            payload.error ?? "unable to place testnet limit close",
          ),
        );
        return;
      }

      const summary = payload.summary;
      const closeSourceLabel =
        priceSource === "current"
          ? "Current price"
          : priceSource === "chart"
            ? "Chart price"
            : "Typed price";

      if (summary.finalResult === "filled") {
        const fullyClosed = normalizedPercent >= 100;
        const relatedLogs = appendSessionLogEntries([
          {
            category: "orders",
            description: `Reduce-only limit close executed at ${closeSourceLabel.toLowerCase()}.`,
            direction: summary.direction,
            eventType: "limit-order-placed",
            pnl: null,
            price: summary.fillPrice,
            size: summary.actualFilledSize,
            source: "Limit Close",
            symbol,
          },
          {
            category: "positions",
            description: fullyClosed
              ? "Position fully closed from reduce-only limit close."
              : `Position reduced ${normalizedPercent}% from reduce-only limit close.`,
            direction: livePosition.direction,
            eventType: fullyClosed ? "position-closed" : "position-reduced",
            pnl: livePosition.pnlUsd * (normalizedPercent / 100),
            price: summary.fillPrice,
            size: summary.actualFilledSize,
            source: "Limit Close",
            symbol,
          },
        ]);
        const realizedPnl = livePosition.pnlUsd * (normalizedPercent / 100);
        if (fullyClosed) {
          updateLatestJournalEntryForClosedTrade(symbol, {
            executionId: summary.placementId,
            exitPrice: summary.fillPrice,
            grossPnl: realizedPnl,
            orderId: summary.limitOrder.id,
            realizedPnl,
            relatedSessionLogIds: relatedLogs.map((log) => log.id),
            size: summary.actualFilledSize,
            timestamp: new Date(summary.timestamp).toISOString(),
          });
        } else {
          updateLatestJournalEntryForReducedTrade(symbol, {
            executionId: summary.placementId,
            grossPnl: realizedPnl,
            orderId: summary.limitOrder.id,
            realizedPnl,
            reducedSize: summary.actualFilledSize,
            relatedSessionLogIds: relatedLogs.map((log) => log.id),
            remainingSize: Math.max(
              livePosition.size - summary.actualFilledSize,
              0,
            ),
            timestamp: new Date(summary.timestamp).toISOString(),
          });
        }
        if (fullyClosed) {
          clearRecentExecutionForSymbol(symbol);
        }
        void refreshPostMutationLiveState();
        showOrderToast(
          "filled",
          "Limit close filled",
          fullyClosed
            ? "Position closed."
            : `Position reduced ${normalizedPercent}%.`,
        );
        return;
      }

      appendSessionLogEntries([
        {
          category: "orders",
          description: `Reduce-only limit close placed for ${normalizedPercent}% at ${formatChartPriceInput(summary.normalizedPrice)}.`,
          direction: summary.direction,
          eventType: "limit-order-placed",
          pnl: null,
          price: summary.normalizedPrice,
          size: summary.normalizedSize,
          source: "Limit Close",
          symbol,
        },
      ]);
      setPendingLimitOrders((currentOrders) => [
        ...currentOrders,
        buildPendingLimitOrder(summary, "limit-close", null, {
          reduceOnly: true,
        }),
      ]);
      setSelectedObject(null);
      void refreshPostMutationLiveState();
      showOrderToast(
        "armed",
        "Limit close armed",
        `${normalizedPercent}% waiting at selected price.`,
      );
    } catch {
      showOrderToast(
        "rejected",
        "Limit close rejected",
        "Connection unavailable.",
      );
    } finally {
      setPositionActionInFlightSymbol((currentSymbol) =>
        currentSymbol === symbol ? null : currentSymbol,
      );
      setExecutionStatusMessage(null);
      setIsExecuting(false);
      setLimitOrderRequestState("idle");
      setLimitClosePricePick(null);
    }
  }

  function handleLimitCloseAtCurrentPrice(
    symbol: HyperliquidSymbol,
    percent: number,
  ) {
    const livePosition = liveExchangePositions.find(
      (position) => position.symbol === symbol,
    );
    const currentPrice =
      symbol === activeSymbol &&
      activeMarketPrice !== null &&
      Number.isFinite(activeMarketPrice)
        ? activeMarketPrice
        : livePosition?.markPrice;

    if (!Number.isFinite(currentPrice) || (currentPrice ?? 0) <= 0) {
      showOrderToast(
        "blocked",
        "Limit close blocked",
        "Current price is unavailable.",
      );
      return;
    }

    void handleLimitClosePosition(
      symbol,
      percent,
      currentPrice as number,
      "current",
    );
  }

  function handleLimitCloseAtPrice(
    symbol: HyperliquidSymbol,
    percent: number,
    price: number,
  ) {
    void handleLimitClosePosition(symbol, percent, price, "typed");
  }

  function handleLimitCloseSelectPrice(
    symbol: HyperliquidSymbol,
    percent: number,
  ) {
    if (symbol !== activeSymbol) {
      showOrderToast(
        "blocked",
        "Chart switch required",
        "Switch to the position chart before picking a limit close price.",
      );
      return;
    }

    setLimitPlacementDirection(null);
    setLimitClosePricePick({
      percent: Math.min(100, Math.max(1, Math.round(percent))),
      symbol,
    });
    showOrderToast(
      "processing",
      "Pick chart price",
      "Select the limit close level on the chart.",
    );
  }

  async function reconcileReducePositionFromLiveState(
    symbol: HyperliquidSymbol,
    initialSize: number,
    payloadRemainingSize?: number | null,
  ) {
    await refreshLivePositionsState({
      force: true,
      fresh: true,
      reason: "critical",
    });
    const refreshedPosition = liveExchangePositionsRef.current.find(
      (position) => position.symbol === symbol,
    );

    return reconcileReducePositionOutcome({
      initialSize,
      payloadRemainingSize,
      refreshedSize: refreshedPosition?.size ?? 0,
    });
  }

  function writeReduceSuccessEffects(
    livePosition: LiveExchangePosition,
    normalizedPercent: number,
    outcome: Extract<ReducePositionReconciliationOutcome, { ok: true }>,
  ) {
    const symbol = livePosition.symbol;
    const pnlRatio =
      livePosition.size > 0
        ? Math.min(1, Math.max(0, outcome.reducedSize / livePosition.size))
        : normalizedPercent / 100;
    const realizedPnl = livePosition.pnlUsd * pnlRatio;
    recordRealizedPnl(realizedPnl);

    if (!outcome.closed) {
      const relatedLogs = appendSessionLogEntries([
        {
          category: "positions",
          description: outcome.reconciledFromRefresh
            ? `Position reduced by ${normalizedPercent}% on Hyperliquid testnet. Exchange state confirmed after refresh.`
            : `Position reduced by ${normalizedPercent}% on Hyperliquid testnet.`,
          direction: livePosition.direction,
          eventType: "position-reduced",
          pnl: realizedPnl,
          price: livePosition.entryPrice,
          size: outcome.reducedSize,
          source: "Reduce Position",
          symbol,
        },
      ]);
      updateLatestJournalEntryForReducedTrade(symbol, {
        grossPnl: realizedPnl,
        realizedPnl,
        reducedSize: outcome.reducedSize,
        relatedSessionLogIds: relatedLogs.map((log) => log.id),
        remainingSize: outcome.remainingSize,
        timestamp: relatedLogs[0]?.timestamp ?? new Date().toISOString(),
      });
      captureReplayFrameForSymbol(symbol, "partial-close", {
        pnl: realizedPnl,
        price: livePosition.entryPrice,
        size: outcome.reducedSize,
      });
      showOrderToast(
        "filled",
        `Position reduced ${normalizedPercent}%`,
        outcome.reconciledFromRefresh
          ? "State confirmed after refresh."
          : undefined,
      );
      return;
    }

    clearRecentExecutionForSymbol(symbol);
    const relatedLogs = appendSessionLogEntries([
      {
        category: "positions",
        description: outcome.reconciledFromRefresh
          ? "Position fully closed after reduce action. Exchange state confirmed after refresh."
          : "Position fully closed after reduce action.",
        direction: livePosition.direction,
        eventType: "position-closed",
        pnl: realizedPnl,
        price: livePosition.entryPrice,
        size: livePosition.size,
        source: "Reduce Position",
        symbol,
      },
    ]);
    const openJournalEntry = getLatestOpenJournalEntry(symbol);
    updateLatestJournalEntryForClosedTrade(symbol, {
      exitPrice: activeMarketPrice ?? livePosition.entryPrice,
      grossPnl: realizedPnl,
      realizedPnl,
      relatedSessionLogIds: relatedLogs.map((log) => log.id),
      size: livePosition.size,
      timestamp: relatedLogs[0]?.timestamp ?? new Date().toISOString(),
    });
    if (openJournalEntry) {
      appendExitReplayFrameToJournalEntry(openJournalEntry.id, {
        pnl: realizedPnl,
        price: activeMarketPrice ?? livePosition.entryPrice,
        size: livePosition.size,
      });
    }
    showOrderToast("filled", "Position closed");
  }

  async function handleReducePosition(
    symbol: HyperliquidSymbol,
    percent: number,
  ) {
    if (positionActionInFlightSymbol === symbol) {
      return;
    }

    const livePosition = liveExchangePositionsRef.current.find(
      (position) => position.symbol === symbol,
    );

    if (
      !livePosition ||
      !Number.isFinite(livePosition.size) ||
      livePosition.size <= 0
    ) {
      showToast("Reduce position failed — no live position exists");
      return;
    }

    const normalizedPercent = Math.min(100, Math.max(1, Math.round(percent)));
    setPositionActionInFlightSymbol(symbol);
    setExecutionStatusMessage(`Reducing position ${normalizedPercent}%...`);

    try {
      const { json: payload, response } = await fetchJsonWithTimeout<{
        error?: string;
        remainingSize?: number;
      }>(
        (signal) =>
          fetch("/api/reduce-position", {
            body: JSON.stringify({ percent: normalizedPercent, symbol }),
            headers: {
              "Content-Type": "application/json",
            },
            method: "POST",
            signal,
          }),
        { timeoutMs: RECOVERABLE_ACTION_TIMEOUT_MS },
      );

      if (!response.ok) {
        const reconciledOutcome = await reconcileReducePositionFromLiveState(
          symbol,
          livePosition.size,
        );

        if (reconciledOutcome.ok) {
          writeReduceSuccessEffects(
            livePosition,
            normalizedPercent,
            reconciledOutcome,
          );
          await refreshPostMutationLiveState();
          return;
        }

        showToast(
          formatExecutionErrorMessage(
            payload.error ?? "unable to reduce testnet position",
          ),
        );
        return;
      }

      const outcome = await reconcileReducePositionFromLiveState(
        symbol,
        livePosition.size,
        payload.remainingSize,
      );

      if (!outcome.ok) {
        showToast(
          "Reduce position failed — live position size did not update after reduce attempt.",
        );
        return;
      }

      writeReduceSuccessEffects(livePosition, normalizedPercent, outcome);
      await refreshPostMutationLiveState();
    } catch (error) {
      const reconciledOutcome = await reconcileReducePositionFromLiveState(
        symbol,
        livePosition.size,
      );

      if (reconciledOutcome.ok) {
        writeReduceSuccessEffects(
          livePosition,
          normalizedPercent,
          reconciledOutcome,
        );
        await refreshPostMutationLiveState();
      } else {
        showToast(
          isFetchJsonTimeoutError(error)
            ? "Reduce request timed out. Refreshing live position state."
            : "Execution failed — connection unavailable",
        );
        void refreshPostMutationLiveState();
      }
    } finally {
      setPositionActionInFlightSymbol((currentSymbol) =>
        currentSymbol === symbol ? null : currentSymbol,
      );
      setExecutionStatusMessage(null);
    }
  }

  async function handleReversePosition(symbol: HyperliquidSymbol) {
    if (positionActionInFlightSymbol === symbol) {
      return;
    }

    const livePosition = liveExchangePositions.find(
      (position) => position.symbol === symbol,
    );

    if (
      !livePosition ||
      !Number.isFinite(livePosition.size) ||
      livePosition.size <= 0
    ) {
      showToast("Reverse position failed — no live position exists");
      return;
    }

    const reverseDirection =
      livePosition.direction === "long" ? "short" : "long";
    const disciplineDecision = evaluateCurrentDisciplineRiskGate({
      actionType: "reverse_position",
      currentPosition: livePosition,
      orderType: "market",
      requestedTrades: 1,
      side: reverseDirection,
      size: livePosition.size,
      source: "manual",
      symbol,
    });

    if (disciplineDecision.decision === "blocked") {
      showDisciplineRiskGateBlockedToast(disciplineDecision, {
        direction: reverseDirection,
        price: activeMarketPrice ?? livePosition.entryPrice,
        size: livePosition.size,
      });
      return;
    }

    setPositionActionInFlightSymbol(symbol);
    setExecutionStatusMessage("Reversing position...");

    try {
      const response = await fetch("/api/reverse-position", {
        body: JSON.stringify({ symbol }),
        headers: {
          "Content-Type": "application/json",
        },
        method: "POST",
      });

      const payload = (await response.json()) as {
        error?: string;
      } & ServerDisciplineBlockedPayload;

      if (!response.ok) {
        if (
          showServerDisciplineBlockedPayload(payload, {
            direction: reverseDirection,
            price: activeMarketPrice ?? livePosition.entryPrice,
            size: livePosition.size,
            symbol,
          })
        ) {
          return;
        }

        showToast(
          formatExecutionErrorMessage(
            payload.error ?? "unable to reverse testnet position",
          ),
        );
        return;
      }

      setActiveTradePlan((currentTradePlan) =>
        currentTradePlan?.symbol === symbol ? null : currentTradePlan,
      );
      setDraftTradePlan((currentDraftTradePlan) =>
        currentDraftTradePlan?.symbol === symbol ? null : currentDraftTradePlan,
      );
      setSelectedObject(null);
      recordRealizedPnl(livePosition.pnlUsd);
      const relatedLogs = appendSessionLogEntries([
        {
          category: "positions",
          description: "Position reversed on Hyperliquid testnet.",
          direction: livePosition.direction === "long" ? "short" : "long",
          eventType: "position-reversed",
          pnl: livePosition.pnlUsd,
          price: livePosition.entryPrice,
          size: livePosition.size,
          source: "Reverse Position",
          symbol,
        },
      ]);
      captureReplayFrameForSymbol(symbol, "reverse", {
        pnl: livePosition.pnlUsd ?? null,
        price: activeMarketPrice ?? livePosition.entryPrice,
        size: livePosition.size,
      });
      const openJournalEntry = getLatestOpenJournalEntry(symbol);
      updateLatestJournalEntryForReversedTrade(symbol, {
        exitPrice: activeMarketPrice ?? livePosition.entryPrice,
        grossPnl: livePosition.pnlUsd ?? null,
        realizedPnl: livePosition.pnlUsd ?? null,
        relatedSessionLogIds: relatedLogs.map((log) => log.id),
        size: livePosition.size,
        timestamp: relatedLogs[0]?.timestamp ?? new Date().toISOString(),
      });
      if (openJournalEntry) {
        appendExitReplayFrameToJournalEntry(openJournalEntry.id, {
          pnl: livePosition.pnlUsd ?? null,
          price: activeMarketPrice ?? livePosition.entryPrice,
          size: livePosition.size,
        });
      }
      clearRecentExecutionForSymbol(symbol);
      await refreshPostMutationLiveState();
      showOrderToast("filled", "Position reversed");
    } catch {
      showOrderToast("rejected", "Order rejected", "Connection unavailable.");
    } finally {
      setPositionActionInFlightSymbol((currentSymbol) =>
        currentSymbol === symbol ? null : currentSymbol,
      );
      setExecutionStatusMessage(null);
    }
  }

  async function handleCancelAllOrders() {
    if (bulkSafetyActionInFlight) {
      return;
    }

    setBulkSafetyActionInFlight("cancel-all");
    setExecutionStatusMessage("Processing cancel all");

    try {
      const response = await fetch("/api/cancel-all-orders", {
        method: "POST",
      });
      const payload = (await response.json()) as {
        canceledOrderCount?: number;
        error?: string;
      };

      if (!response.ok) {
        showToast(
          formatExecutionErrorMessage(
            payload.error ?? "unable to cancel all testnet orders",
          ),
        );
        return;
      }

      const canceledOrderCount =
        typeof payload.canceledOrderCount === "number"
          ? payload.canceledOrderCount
          : 0;

      if (canceledOrderCount <= 0) {
        showToast("No pending orders to cancel", 0, "neutral");
        return;
      }

      setPendingLimitOrders([]);
      setLivePendingOrders([]);
      clearAllDerivedZoneOrderConfig();
      setSelectedObject((currentSelection) =>
        currentSelection?.type === "pending-order" ||
        currentSelection?.type === "zone"
          ? null
          : currentSelection,
      );
      appendSessionLogEntries([
        {
          category: "orders",
          description: `${canceledOrderCount} pending order${canceledOrderCount === 1 ? "" : "s"} canceled from the bulk action.`,
          direction: null,
          eventType: "cancel-all-orders-used",
          pnl: null,
          price: null,
          size: null,
          source: "Cancel All Orders",
          symbol: null,
        },
      ]);
      await refreshPostMutationLiveState();
      showOrderToast("canceled", "All pending orders canceled");
    } catch {
      showOrderToast(
        "rejected",
        "Cancel all rejected",
        "Connection unavailable.",
      );
    } finally {
      setBulkSafetyActionInFlight(null);
      setExecutionStatusMessage(null);
    }
  }

  async function handleCloseAll() {
    if (bulkSafetyActionInFlight) {
      return;
    }

    if (
      !window.confirm(
        "Close All will cancel all pending orders, remove live TP/SL protection, and market-close all live positions on Hyperliquid testnet. Continue?",
      )
    ) {
      return;
    }

    setBulkSafetyActionInFlight("close-all");
    setExecutionStatusMessage("Closing all exposure...");
    const realizedPnlSnapshot = liveExchangePositions.reduce(
      (totalPnl, position) => {
        if (!Number.isFinite(position.pnlUsd)) {
          return totalPnl;
        }

        return totalPnl + position.pnlUsd;
      },
      0,
    );

    try {
      const response = await fetch("/api/close-all", {
        method: "POST",
      });
      const payload = (await response.json()) as {
        canceledPendingOrderCount?: number;
        canceledProtectionOrderCount?: number;
        closedPositionCount?: number;
        error?: string;
      };

      if (!response.ok) {
        showToast(
          formatExecutionErrorMessage(
            payload.error ?? "unable to close all testnet exposure",
          ),
        );
        return;
      }

      const canceledPendingOrderCount =
        typeof payload.canceledPendingOrderCount === "number"
          ? payload.canceledPendingOrderCount
          : 0;
      const canceledProtectionOrderCount =
        typeof payload.canceledProtectionOrderCount === "number"
          ? payload.canceledProtectionOrderCount
          : 0;
      const closedPositionCount =
        typeof payload.closedPositionCount === "number"
          ? payload.closedPositionCount
          : 0;

      if (
        canceledPendingOrderCount <= 0 &&
        canceledProtectionOrderCount <= 0 &&
        closedPositionCount <= 0
      ) {
        showToast("No live exposure to close", 0, "neutral");
        return;
      }

      setPendingLimitOrders([]);
      setLivePendingOrders([]);
      clearAllDerivedZoneOrderConfig();
      setActivePosition(null);
      setActiveTradePlan(null);
      setDraftTradePlan(null);
      setLiveExchangePositions([]);
      latestExecutionSummaryRef.current = null;
      setSelectedObject(null);
      recordRealizedPnl(realizedPnlSnapshot);
      const relatedLogs = appendSessionLogEntries([
        {
          category: "positions",
          description: `Close All flattened ${closedPositionCount} position${closedPositionCount === 1 ? "" : "s"} and cleared ${canceledPendingOrderCount} pending order${canceledPendingOrderCount === 1 ? "" : "s"}.`,
          direction: null,
          eventType: "close-all-used",
          pnl: realizedPnlSnapshot,
          price: null,
          size: null,
          source: "Close All",
          symbol: null,
        },
      ]);
      const closeAllJournalSymbols = resolveCloseAllJournalEntryTargets(
        journalEntriesRef.current,
        liveExchangePositions,
      );
      closeAllJournalSymbols.forEach((symbol) => {
        const closedPosition = liveExchangePositions.find(
          (position) => position.symbol === symbol,
        );

        if (!closedPosition) {
          return;
        }

        const openJournalEntry = getLatestOpenJournalEntry(symbol);
        const exitPrice =
          symbol === activeSymbol
            ? activeMarketPrice
            : closedPosition.markPrice;
        const realizedPnl = Number.isFinite(closedPosition.pnlUsd)
          ? closedPosition.pnlUsd
          : null;

        captureReplayFrameForSymbol(symbol, "close-all", {
          pnl: realizedPnl,
          price: exitPrice,
          size: closedPosition.size,
        });
        updateLatestJournalEntryForClosedTrade(symbol, {
          exitPrice,
          grossPnl: realizedPnl,
          realizedPnl,
          relatedSessionLogIds: relatedLogs.map((log) => log.id),
          size: closedPosition.size,
          timestamp: relatedLogs[0]?.timestamp ?? new Date().toISOString(),
        });
        if (openJournalEntry) {
          appendExitReplayFrameToJournalEntry(openJournalEntry.id, {
            pnl: realizedPnl,
            price: exitPrice,
            size: closedPosition.size,
          });
        }
      });
      await refreshPostMutationLiveState();
      showOrderToast(
        "filled",
        "Close All confirmed",
        "Account exposure is flat.",
      );
    } catch {
      showOrderToast(
        "rejected",
        "Close All rejected",
        "Connection unavailable.",
      );
    } finally {
      setBulkSafetyActionInFlight(null);
      setExecutionStatusMessage(null);
    }
  }

  type LiveStateRefreshOptions = {
    force?: boolean;
    fresh?: boolean;
    reason?: LiveStateRefreshReason;
  };

  function getLiveStateRefreshReason(options: LiveStateRefreshOptions) {
    return options.reason ?? (options.fresh ? "critical" : "background");
  }

  function shouldSkipLiveStateResourceRefresh(
    resource: LiveStateBackoffResource,
    reason: LiveStateRefreshReason,
    now: number,
  ) {
    return shouldSkipLiveStateRefresh({
      now,
      reason,
      resource,
      state: liveStateBackoffRef.current,
    });
  }

  function recordLiveStateRefreshResult(
    resource: LiveStateBackoffResource,
    result: "success" | "failure",
    now: number,
  ) {
    liveStateBackoffRef.current =
      result === "success"
        ? recordLiveStateRefreshSuccess(liveStateBackoffRef.current, resource)
        : recordLiveStateRefreshFailure(
            liveStateBackoffRef.current,
            resource,
            now,
          );
  }

  function getAccountRefreshCooldownMs(reason: LiveStateRefreshReason) {
    if (reason === "critical") {
      return LIVE_STATE_REFRESH_COOLDOWN_MS;
    }

    return document.visibilityState === "visible"
      ? ACCOUNT_REFRESH_VISIBLE_MS
      : ACCOUNT_REFRESH_HIDDEN_MS;
  }

  async function refreshAccountState(
    options: LiveStateRefreshOptions & {
      logFailure?: boolean;
    } = {},
  ) {
    const { force = false, fresh = false, logFailure = true } = options;
    const reason = getLiveStateRefreshReason(options);
    const currentInFlightRequest = accountRefreshInFlightRef.current;

    if (currentInFlightRequest && !fresh) {
      return currentInFlightRequest;
    }

    const now = Date.now();

    if (shouldSkipLiveStateResourceRefresh("account", reason, now)) {
      return Promise.resolve();
    }

    if (
      !force &&
      now - accountRefreshLastStartedAtRef.current <
        getAccountRefreshCooldownMs(reason)
    ) {
      return Promise.resolve();
    }

    accountRefreshLastStartedAtRef.current = now;
    const requestId = accountRefreshRequestIdRef.current + 1;
    accountRefreshRequestIdRef.current = requestId;

    const refreshPromise = (async () => {
      try {
        const accountRefreshSymbol = isChartOnlyMarketSymbol(
          activeSymbolRef.current,
        )
          ? hyperliquidSymbols[0].symbol
          : (activeSymbolRef.current as HyperliquidSymbol);
        const params = new URLSearchParams({
          symbol: accountRefreshSymbol,
        });

        if (fresh) {
          params.set("fresh", "1");
        }

        const response = await fetch(`/api/account?${params.toString()}`, {
          cache: "no-store",
        });
        const payload = (await response.json()) as {
          accountValue?: number;
          balances?: AccountBalanceRecord[];
          fundingHistory?: AccountFundingHistoryRecord[];
          orderHistory?: AccountOrderHistoryRecord[];
          tradeHistory?: AccountTradeHistoryRecord[];
          availableToTrade?: number;
          availableToTradeBySide?: Partial<Record<TradeDirection, number>>;
          error?: string;
        };

        if (!response.ok || payload.error) {
          recordLiveStateRefreshResult("account", "failure", Date.now());
          if (logFailure) {
            console.warn(
              "[portal] unable to refresh Hyperliquid account state",
              payload.error ?? `HTTP ${response.status}`,
            );
          }
          return;
        }

        if (accountRefreshRequestIdRef.current !== requestId) {
          return;
        }

        setAvailableToTrade(
          typeof payload.availableToTrade === "number" &&
            Number.isFinite(payload.availableToTrade)
            ? payload.availableToTrade
            : null,
        );
        setAvailableToTradeBySide({
          long:
            typeof payload.availableToTradeBySide?.long === "number" &&
            Number.isFinite(payload.availableToTradeBySide.long)
              ? payload.availableToTradeBySide.long
              : typeof payload.availableToTrade === "number" &&
                  Number.isFinite(payload.availableToTrade)
                ? payload.availableToTrade
                : null,
          short:
            typeof payload.availableToTradeBySide?.short === "number" &&
            Number.isFinite(payload.availableToTradeBySide.short)
              ? payload.availableToTradeBySide.short
              : typeof payload.availableToTrade === "number" &&
                  Number.isFinite(payload.availableToTrade)
                ? payload.availableToTrade
                : null,
        });
        setAccountValue(
          typeof payload.accountValue === "number" &&
            Number.isFinite(payload.accountValue)
            ? payload.accountValue
            : null,
        );
        setAccountBalances(
          Array.isArray(payload.balances) ? payload.balances : [],
        );
        setAccountFundingHistory(
          Array.isArray(payload.fundingHistory) ? payload.fundingHistory : [],
        );
        setAccountTradeHistory(
          Array.isArray(payload.tradeHistory) ? payload.tradeHistory : [],
        );
        setAccountOrderHistory(
          Array.isArray(payload.orderHistory) ? payload.orderHistory : [],
        );
        recordLiveStateRefreshResult("account", "success", Date.now());
      } catch (error) {
        recordLiveStateRefreshResult("account", "failure", Date.now());
        if (logFailure) {
          console.warn(
            "[portal] unable to refresh Hyperliquid account state",
            error,
          );
        }
      } finally {
        if (accountRefreshRequestIdRef.current === requestId) {
          accountRefreshInFlightRef.current = null;
        }
      }
    })();

    accountRefreshInFlightRef.current = refreshPromise;
    return refreshPromise;
  }

  function handleAccountActivityAggregateTradesChange(value: boolean) {
    setAccountActivityAggregateTrades(value);
  }

  function handleAccountActivityMarketFilterChange(value: string) {
    setAccountActivityMarketFilter(value);
    setAccountActivityMarketFilterHasSelection(true);
  }

  function handleAccountActivityPositionFilterChange(
    value: AccountActivityPositionFilter,
  ) {
    setAccountActivityPositionFilter(value);
    setAccountActivityPositionFilterHasSelection(true);
  }

  async function refreshLivePositionsState(
    options: LiveStateRefreshOptions = {},
  ) {
    const { force = false, fresh = false } = options;
    const reason = getLiveStateRefreshReason(options);
    const currentInFlightRequest = livePositionsRefreshInFlightRef.current;

    if (currentInFlightRequest && !fresh) {
      livePositionsRefreshQueuedRef.current = true;
      return currentInFlightRequest;
    }

    const now = Date.now();

    if (shouldSkipLiveStateResourceRefresh("live-positions", reason, now)) {
      return Promise.resolve();
    }

    if (
      !force &&
      now - livePositionsLastStartedAtRef.current <
        LIVE_STATE_REFRESH_COOLDOWN_MS
    ) {
      return Promise.resolve();
    }

    livePositionsLastStartedAtRef.current = now;
    const requestId = livePositionsRefreshRequestIdRef.current + 1;
    livePositionsRefreshRequestIdRef.current = requestId;

    const refreshPromise = (async () => {
      try {
        const response = await fetch(
          `/api/live-positions${fresh ? "?fresh=1" : ""}`,
          {
            cache: "no-store",
          },
        );
        const payload = (await response.json()) as {
          error?: string;
          positions?: LiveExchangePosition[];
        };

        if (!response.ok || payload.error) {
          recordLiveStateRefreshResult("live-positions", "failure", Date.now());
          return;
        }

        const nextPositions = Array.isArray(payload.positions)
          ? payload.positions
          : [];
        applyExchangePositions(nextPositions);
        recordLiveStateRefreshResult("live-positions", "success", Date.now());
      } catch {
        recordLiveStateRefreshResult("live-positions", "failure", Date.now());
        // Ignore background refresh failures.
      } finally {
        if (livePositionsRefreshRequestIdRef.current === requestId) {
          livePositionsRefreshInFlightRef.current = null;

          if (livePositionsRefreshQueuedRef.current) {
            livePositionsRefreshQueuedRef.current = false;
            void refreshLivePositionsState({ force: true, fresh });
          }
        }
      }
    })();

    livePositionsRefreshInFlightRef.current = refreshPromise;
    return refreshPromise;
  }

  async function refreshPendingOrders(options: LiveStateRefreshOptions = {}) {
    const { force = false, fresh = false } = options;
    const reason = getLiveStateRefreshReason(options);
    const currentInFlightRequest = pendingOrdersRefreshInFlightRef.current;

    if (currentInFlightRequest && !fresh) {
      pendingOrdersRefreshQueuedRef.current = true;
      return currentInFlightRequest;
    }

    const now = Date.now();

    if (shouldSkipLiveStateResourceRefresh("pending-orders", reason, now)) {
      return Promise.resolve();
    }

    if (
      !force &&
      now - pendingOrdersLastStartedAtRef.current <
        LIVE_STATE_REFRESH_COOLDOWN_MS
    ) {
      return Promise.resolve();
    }

    pendingOrdersLastStartedAtRef.current = now;
    const requestId = pendingOrdersRefreshRequestIdRef.current + 1;
    pendingOrdersRefreshRequestIdRef.current = requestId;

    const refreshPromise = (async () => {
      try {
        const response = await fetch(
          `/api/pending-orders${fresh ? "?fresh=1" : ""}`,
          {
            cache: "no-store",
          },
        );
        const payload = (await response.json()) as {
          error?: string;
          pendingOrders?: LivePendingOrder[];
        };

        if (!response.ok || payload.error) {
          recordLiveStateRefreshResult("pending-orders", "failure", Date.now());
          return;
        }

        setLivePendingOrders(
          Array.isArray(payload.pendingOrders) ? payload.pendingOrders : [],
        );
        recordLiveStateRefreshResult("pending-orders", "success", Date.now());
      } catch {
        recordLiveStateRefreshResult("pending-orders", "failure", Date.now());
        // Ignore background refresh failures.
      } finally {
        if (pendingOrdersRefreshRequestIdRef.current === requestId) {
          pendingOrdersRefreshInFlightRef.current = null;

          if (pendingOrdersRefreshQueuedRef.current) {
            pendingOrdersRefreshQueuedRef.current = false;
            void refreshPendingOrders({ force: true, fresh });
          }
        }
      }
    })();

    pendingOrdersRefreshInFlightRef.current = refreshPromise;
    return refreshPromise;
  }

  async function refreshCriticalLiveState(
    options: LiveStateRefreshOptions = {},
  ) {
    await Promise.all([
      refreshPendingOrders(options),
      refreshLivePositionsState(options),
    ]);
  }

  async function refreshLiveState(options: LiveStateRefreshOptions = {}) {
    await Promise.all([
      refreshAccountState(options),
      refreshPendingOrders(options),
      refreshLivePositionsState(options),
    ]);
  }

  async function refreshPostMutationLiveState() {
    await refreshCriticalLiveState({
      force: true,
      fresh: true,
      reason: "critical",
    });
    void refreshAccountState({ force: true, fresh: true, reason: "critical" });
  }

  async function cancelPendingOrder(
    order: PendingLimitOrder,
    options: { allowZoneCascade?: boolean } = {},
  ): Promise<boolean> {
    if (
      options.allowZoneCascade !== false &&
      order.source === "order-zone" &&
      order.parentZoneId
    ) {
      return deleteZone(order.parentZoneId);
    }

    if (order.status === "canceling" || order.status === "updating") {
      return false;
    }

    setLimitOrderRequestState("canceling");
    setPendingLimitOrders((currentOrders) =>
      currentOrders.map((currentOrder) =>
        currentOrder.id === order.id
          ? {
              ...currentOrder,
              status: "canceling",
            }
          : currentOrder,
      ),
    );

    const cancelId = `cancel-${Date.now()}-${crypto.randomUUID()}`;

    try {
      const response = await fetch("/api/cancel-order", {
        body: JSON.stringify({
          cancelId,
          orderId: order.orderId,
          side: order.direction,
          symbol: order.symbol,
        }),
        headers: {
          "Content-Type": "application/json",
        },
        method: "POST",
      });

      const payload = (await response.json()) as {
        error?: string;
        summary?: PendingOrderCancelSummary;
      };

      if (!response.ok || !payload.summary) {
        setPendingLimitOrders((currentOrders) =>
          currentOrders.map((currentOrder) =>
            currentOrder.id === order.id
              ? {
                  ...currentOrder,
                  status: "live",
                }
              : currentOrder,
          ),
        );
        showToast(
          formatExecutionErrorMessage(
            payload.error ?? "unable to cancel pending order",
          ),
        );
        return false;
      }

      setPendingLimitOrders((currentOrders) =>
        currentOrders.filter((currentOrder) => currentOrder.id !== order.id),
      );
      setSelectedObject((currentSelection) =>
        currentSelection?.type === "pending-order" &&
        currentSelection.id === order.id
          ? null
          : currentSelection,
      );
      setLimitPlacementDirection(null);
      appendSessionLogEntries([
        {
          category: "orders",
          description: `Canceled ${order.symbol} order ${order.orderId}.`,
          direction: order.direction,
          eventType: "limit-order-canceled",
          metadata: {
            orderId: order.orderId,
            placementId: order.placementId,
            reduceOnly: order.reduceOnly,
            source: order.source,
          },
          pnl: null,
          price: order.normalizedPrice,
          size: order.normalizedSize,
          source: "Pending Order",
          symbol: order.symbol,
        },
      ]);
      void refreshPostMutationLiveState();
      showOrderToast("canceled", "Pending order canceled");
      return true;
    } catch {
      setPendingLimitOrders((currentOrders) =>
        currentOrders.map((currentOrder) =>
          currentOrder.id === order.id
            ? {
                ...currentOrder,
                status: "live",
              }
            : currentOrder,
        ),
      );
      showOrderToast("rejected", "Cancel rejected", "Connection unavailable.");
      return false;
    } finally {
      setLimitOrderRequestState((currentState) =>
        currentState === "canceling" ? "idle" : currentState,
      );
    }
  }

  async function handleAccountActivityCancelOrder(
    symbol: HyperliquidSymbol,
    direction: TradeDirection,
    orderId: number,
  ) {
    const matchingPendingOrder = pendingLimitOrdersRef.current.find(
      (order) => order.orderId === orderId,
    );

    if (matchingPendingOrder) {
      await cancelPendingOrder(matchingPendingOrder);
      return;
    }

    const cancelId = `account-activity-cancel-${Date.now()}-${crypto.randomUUID()}`;

    setExecutionStatusMessage("Processing cancel");

    try {
      const response = await fetch("/api/cancel-order", {
        body: JSON.stringify({
          cancelId,
          orderId,
          side: direction,
          symbol,
        }),
        headers: {
          "Content-Type": "application/json",
        },
        method: "POST",
      });

      const payload = (await response.json()) as {
        error?: string;
        summary?: PendingOrderCancelSummary;
      };

      if (!response.ok || !payload.summary) {
        showToast(
          formatExecutionErrorMessage(
            payload.error ?? "unable to cancel pending order",
          ),
        );
        return;
      }

      setPendingLimitOrders((currentOrders) =>
        currentOrders.filter((order) => order.orderId !== orderId),
      );
      setLivePendingOrders((currentOrders) =>
        currentOrders.filter((order) => order.orderId !== orderId),
      );
      appendSessionLogEntries([
        {
          category: "orders",
          description: `Canceled ${symbol} order ${orderId}.`,
          direction,
          eventType: "limit-order-canceled",
          pnl: null,
          price: null,
          size: null,
          source: "Open Orders",
          symbol,
        },
      ]);
      await refreshPostMutationLiveState();
      showOrderToast("canceled", "Order canceled");
    } catch {
      showOrderToast("rejected", "Cancel rejected", "Connection unavailable.");
    } finally {
      setExecutionStatusMessage(null);
    }
  }

  async function handlePendingOrderCommit(
    order: PendingLimitOrder,
    nextPrice: number,
  ): Promise<boolean> {
    if (order.status === "canceling" || order.status === "updating") {
      return false;
    }

    if (!Number.isFinite(nextPrice) || nextPrice <= 0) {
      showOrderToast("blocked", "Order update blocked", "Invalid price.");
      return false;
    }

    const currentPendingOrder =
      pendingLimitOrdersRef.current.find(
        (currentOrder) => currentOrder.id === order.id,
      ) ??
      (order.orderId === null
        ? null
        : (() => {
            const liveOrder = livePendingOrdersRef.current.find(
              (currentOrder) => currentOrder.orderId === order.orderId,
            );

            return liveOrder && isChartRenderableLivePendingOrder(liveOrder)
              ? livePendingOrderToChartPendingLimitOrder(liveOrder)
              : null;
          })());

    if (!currentPendingOrder) {
      showOrderToast(
        "blocked",
        "Order update blocked",
        "Order is no longer active.",
      );
      return false;
    }

    if (isPriceInsideNoTradeZone(nextPrice)) {
      const noTradeZoneDecision = evaluateCurrentDisciplineRiskGate({
        actionType: "limit_order",
        existingOrder: {
          id: order.id,
          orderId: order.orderId,
          reduceOnly: order.reduceOnly,
          side: order.direction,
          size: order.normalizedSize,
        },
        nextOrder: {
          id: order.id,
          orderId: order.orderId,
          reduceOnly: order.reduceOnly,
          side: order.direction,
          size: order.normalizedSize,
        },
        noTradeZoneActive: true,
        orderType: "limit",
        requestedTrades: 1,
        side: order.direction,
        size: order.normalizedSize,
        source:
          order.source === "mid-zone" || order.source === "order-zone"
            ? "order_zone"
            : "manual",
        symbol: order.symbol,
      });
      showDisciplineRiskGateBlockedToast(noTradeZoneDecision, {
        direction: order.direction,
        price: nextPrice,
        size: order.normalizedSize,
      });
      if (noTradeZoneDecision.decision === "blocked") {
        return false;
      }
    }

    const disciplineDecision = evaluateCurrentDisciplineRiskGate({
      actionType: "limit_order",
      existingOrder: {
        id: order.id,
        orderId: order.orderId,
        reduceOnly: order.reduceOnly,
        side: order.direction,
        size: order.normalizedSize,
      },
      nextOrder: {
        id: order.id,
        orderId: order.orderId,
        reduceOnly: order.reduceOnly,
        side: order.direction,
        size: order.normalizedSize,
      },
      orderType: "limit",
      requestedTrades: 1,
      side: order.direction,
      size: order.normalizedSize,
      source:
        order.source === "mid-zone" || order.source === "order-zone"
          ? "order_zone"
          : "manual",
      symbol: order.symbol,
    });

    if (disciplineDecision.decision === "blocked") {
      showDisciplineRiskGateBlockedToast(disciplineDecision, {
        direction: order.direction,
        price: nextPrice,
        size: order.normalizedSize,
      });
      return false;
    }

    setPendingLimitOrders((currentOrders) =>
      currentOrders.map((currentOrder) =>
        currentOrder.id === order.id
          ? {
              ...currentOrder,
              status: "updating",
            }
          : currentOrder,
      ),
    );
    setLimitOrderRequestState("updating");

    const replaceId = `replace-${Date.now()}-${crypto.randomUUID()}`;

    try {
      const response = await fetch("/api/replace-order", {
        body: JSON.stringify({
          orderId: order.orderId,
          price: nextPrice,
          replaceId,
          side: order.direction,
          size: order.normalizedSize,
          symbol: order.symbol,
        }),
        headers: {
          "Content-Type": "application/json",
        },
        method: "POST",
      });

      const payload = (await response.json()) as {
        error?: string;
        summary?: PendingOrderReplaceSummary;
      } & ServerDisciplineBlockedPayload;

      if (!response.ok || !payload.summary) {
        setPendingLimitOrders((currentOrders) =>
          currentOrders.map((currentOrder) =>
            currentOrder.id === order.id
              ? {
                  ...currentOrder,
                  status: "live",
                }
              : currentOrder,
          ),
        );
        if (
          showServerDisciplineBlockedPayload(payload, {
            direction: order.direction,
            price: nextPrice,
            size: order.normalizedSize,
            symbol: order.symbol,
          })
        ) {
          return false;
        }

        showToast(
          formatExecutionErrorMessage(
            payload.error ?? "unable to update pending order",
          ),
        );
        return false;
      }

      const summary = payload.summary;

      if (summary.finalResult === "filled") {
        const relatedLogs = appendSessionLogEntries([
          {
            category: "orders",
            description: "Pending order filled after price update.",
            direction: summary.direction,
            eventType: "pending-order-filled",
            pnl: null,
            price: summary.fillPrice,
            size: summary.actualFilledSize,
            source: "Pending Order Update",
            symbol: summary.symbol,
          },
          {
            category: "positions",
            description: "Position opened from pending order fill.",
            direction: summary.direction,
            eventType: "position-opened",
            pnl: null,
            price: summary.fillPrice,
            size: summary.actualFilledSize,
            source: "Pending Order Update",
            symbol: summary.symbol,
          },
        ]);
        createOrUpdateJournalEntryForOrderFill({
          ...getJournalEntryClassification({ orderSource: order.source }),
          direction: summary.direction,
          entryPrice: summary.fillPrice,
          executionId: summary.replaceId,
          orderId: summary.replacementOrder.id,
          relatedSessionLogIds: relatedLogs.map((entry) => entry.id),
          size: summary.actualFilledSize,
          symbol: summary.symbol,
          timestamp: new Date(summary.timestamp).toISOString(),
        });
        setActivePosition({
          createdAt: new Date(summary.timestamp).toISOString(),
          direction: summary.direction,
          entry: summary.fillPrice,
          entryOrderId: summary.replacementOrder.id,
          executionId: summary.replaceId,
          id: `${summary.symbol}-position-${summary.replaceId}`,
          size: summary.actualFilledSize,
          symbol: summary.symbol,
        });
        upsertConfirmedFillPosition({
          actualFilledSize: summary.actualFilledSize,
          direction: summary.direction,
          entryOrderId: summary.replacementOrder.id,
          executionId: summary.replaceId,
          fillPrice: summary.fillPrice,
          finalResult: summary.finalResult,
          intendedSize: summary.intendedSize,
          normalizedSize: summary.normalizedSize,
          symbol: summary.symbol,
          timestamp: summary.timestamp,
        });
        setPendingLimitOrders((currentOrders) =>
          currentOrders.filter((currentOrder) => currentOrder.id !== order.id),
        );
        setActiveTradePlan(null);
        setDraftTradePlan(null);
        setSelectedObject(null);
        setLimitPlacementDirection(null);
        void refreshPostMutationLiveState();
        showOrderToast(
          "filled",
          "Pending order filled",
          "Update confirmed and entry line anchored to fill.",
        );
        return true;
      }

      if (summary.finalResult === "already closed") {
        setPendingLimitOrders((currentOrders) =>
          currentOrders.filter((currentOrder) => currentOrder.id !== order.id),
        );
        setSelectedObject((currentSelection) =>
          currentSelection?.type === "pending-order" &&
          currentSelection.id === order.id
            ? null
            : currentSelection,
        );
        void refreshPostMutationLiveState();
        showOrderToast(
          "blocked",
          "Order update blocked",
          "Order is no longer live.",
        );
        return false;
      }

      if (summary.finalResult === "restored") {
        setPendingLimitOrders((currentOrders) =>
          currentOrders.map((currentOrder) =>
            currentOrder.id === order.id
              ? {
                  ...currentOrder,
                  normalizedPrice: summary.normalizedPrice,
                  normalizedSize: summary.normalizedSize,
                  orderId: summary.replacementOrder.id,
                  requestedPrice: summary.intendedPrice,
                  requestedSize: summary.intendedSize,
                  status: "live",
                }
              : currentOrder,
          ),
        );
        void refreshPostMutationLiveState();
        showOrderToast(
          "updated",
          "Original order restored",
          "Price update did not replace the resting order.",
        );
        return false;
      }

      setPendingLimitOrders((currentOrders) =>
        currentOrders.map((currentOrder) =>
          currentOrder.id === order.id
            ? {
                ...currentOrder,
                normalizedPrice: summary.normalizedPrice,
                normalizedSize: summary.normalizedSize,
                orderId: summary.replacementOrder.id,
                requestedPrice: summary.intendedPrice,
                requestedSize: summary.intendedSize,
                status: "live",
              }
            : currentOrder,
        ),
      );
      void refreshPostMutationLiveState();
      showOrderToast("updated", "Pending order updated");
      return true;
    } catch {
      setPendingLimitOrders((currentOrders) =>
        currentOrders.map((currentOrder) =>
          currentOrder.id === order.id
            ? {
                ...currentOrder,
                status: "live",
              }
            : currentOrder,
        ),
      );
      showOrderToast(
        "rejected",
        "Order update rejected",
        "Connection unavailable.",
      );
      return false;
    } finally {
      setLimitOrderRequestState((currentState) =>
        currentState === "updating" ? "idle" : currentState,
      );
    }
  }

  type PendingOrderPlacementMetadata = {
    orderZoneCount?: number | null;
    orderZoneDistribution?: OrderZoneDistribution | null;
    orderZoneIndex?: number | null;
    reduceOnly?: boolean;
  };

  function isChartRenderableLivePendingOrder(order: LivePendingOrder) {
    const triggerType = order.triggerType?.trim() ?? "";

    return (
      Number.isFinite(order.price) &&
      order.price > 0 &&
      (triggerType.length === 0 || /^limit$/i.test(triggerType))
    );
  }

  function livePendingOrderToChartPendingLimitOrder(
    order: LivePendingOrder,
  ): PendingLimitOrder {
    return {
      createdAt: order.createdAt,
      direction: order.direction,
      id: `${order.symbol}-exchange-pending-${order.orderId}`,
      normalizedPrice: order.price,
      normalizedSize: Math.abs(order.size),
      orderId: order.orderId,
      orderZoneCount: null,
      orderZoneDistribution: null,
      orderZoneIndex: null,
      parentZoneId: null,
      placementId: `exchange-${order.orderId}`,
      reduceOnly: order.reduceOnly === true,
      requestedPrice: order.price,
      requestedSize: Math.abs(order.originalSize ?? order.size),
      source: "horizontal-line",
      status: "live",
      symbol: order.symbol,
    };
  }

  function buildPendingLimitOrder(
    summary: Pick<
      LimitOrderPlacementSummary | OrderZonePlacementSummaryItem,
      | "direction"
      | "intendedPrice"
      | "intendedSize"
      | "limitOrder"
      | "normalizedPrice"
      | "normalizedSize"
      | "placementId"
      | "symbol"
      | "timestamp"
    >,
    source: PendingLimitOrder["source"],
    parentZoneId: string | null,
    metadata: PendingOrderPlacementMetadata = {},
  ): PendingLimitOrder {
    return {
      createdAt: new Date(summary.timestamp).toISOString(),
      direction: summary.direction,
      id: `${summary.symbol}-pending-${summary.placementId}`,
      normalizedPrice: summary.normalizedPrice,
      normalizedSize: summary.normalizedSize,
      orderId: summary.limitOrder.id,
      orderZoneCount: metadata.orderZoneCount ?? null,
      orderZoneDistribution: metadata.orderZoneDistribution ?? null,
      orderZoneIndex: metadata.orderZoneIndex ?? null,
      parentZoneId,
      placementId: summary.placementId,
      reduceOnly: metadata.reduceOnly === true,
      requestedPrice: summary.intendedPrice,
      requestedSize: summary.intendedSize,
      source,
      status: "live",
      symbol: summary.symbol,
    };
  }

  function getActiveSymbolLivePositionSnapshot() {
    const symbol = activeSymbol as HyperliquidSymbol;

    return (
      liveExchangePositionsRef.current.find(
        (position) => position.symbol === symbol,
      ) ??
      (activePositionRef.current?.symbol === symbol
        ? activePositionRef.current
        : null)
    );
  }

  async function requestLimitOrderPlacement(
    price: number,
    direction: TradeDirection,
    size: number,
    placementId: string,
    options: {
      reduceOnly?: boolean;
      symbol?: HyperliquidSymbol;
    } = {},
  ) {
    const response = await fetch("/api/limit-order", {
      body: JSON.stringify({
        placementId,
        price,
        reduceOnly: options.reduceOnly === true,
        side: direction,
        size,
        symbol: options.symbol ?? activeSymbol,
      }),
      headers: {
        "Content-Type": "application/json",
      },
      method: "POST",
    });

    const payload = (await response.json()) as {
      error?: string;
      summary?: LimitOrderPlacementSummary;
    } & ServerDisciplineBlockedPayload;

    return {
      ok: response.ok && !!payload.summary,
      payload,
    };
  }

  async function handleLimitOrderPlacement(
    price: number,
    direction: TradeDirection,
    source: PendingLimitOrder["source"] = "horizontal-line",
    parentZoneId: string | null = null,
    metadata: PendingOrderPlacementMetadata = {},
  ): Promise<boolean> {
    if (isChartOnlyMarketSymbol(activeSymbol)) {
      showOrderToast(
        "blocked",
        "Chart-only index",
        "Use this as a Magic Trade trigger source.",
      );
      return false;
    }

    const limitOrderSize = getExecutableMarketSizeForSymbol(
      activeSymbol as HyperliquidSymbol,
      direction,
    );

    const placementGuard = evaluateLimitOrderPlacementGuard(
      { direction, reduceOnly: false },
      getActiveSymbolLivePositionSnapshot(),
    );

    if (!placementGuard.allowed) {
      showOrderToast("blocked", "Limit order blocked", placementGuard.reason);
      return false;
    }

    if (!Number.isFinite(price) || price <= 0) {
      showOrderToast("blocked", "Limit order blocked", "Invalid price.");
      return false;
    }

    if (isExecuting) {
      showOrderToast(
        "blocked",
        "Execution blocked",
        "Request already in progress.",
      );
      return false;
    }

    if (limitOrderSize <= 0) {
      showOrderToast("blocked", "Limit order blocked", "Size is too small.");
      return false;
    }

    const limitOrderLeverage = getSelectedTradeLeverageForSymbol(
      activeSymbol as HyperliquidSymbol,
    );
    const marginBlockReason = getMagicTradeMarginAllocationBlockReason({
      actionLabel: "Limit order",
      direction,
      requestedMarginUsd:
        limitOrderLeverage > 0
          ? (limitOrderSize * price) / limitOrderLeverage
          : null,
    });

    if (marginBlockReason) {
      showToast(marginBlockReason, 0, "neutral");
      return false;
    }

    const disciplineDecision = evaluateCurrentDisciplineRiskGate({
      actionType: "limit_order",
      currentPosition: getActiveSymbolLivePositionSnapshot(),
      nextOrder: {
        reduceOnly: false,
        side: direction,
        size: limitOrderSize,
      },
      noTradeZoneActive: isPriceInsideNoTradeZone(price),
      orderType: "limit",
      requestedTrades: 1,
      side: direction,
      size: limitOrderSize,
      source:
        source === "mid-zone" || source === "order-zone"
          ? "order_zone"
          : "manual",
      symbol: activeSymbol,
    });

    if (disciplineDecision.decision === "blocked") {
      showDisciplineRiskGateBlockedToast(disciplineDecision, {
        direction,
        price,
        size: limitOrderSize,
      });
      return false;
    }

    const placementId = `limit-${Date.now()}-${crypto.randomUUID()}`;
    setLimitOrderToastContext(
      buildLimitOrderToastReceipt({
        direction,
        price,
        size: limitOrderSize,
        symbol: activeSymbol,
      }),
    );
    setDockTradeDirection(direction);
    setLimitOrderRequestState("placing");
    setIsExecuting(true);

    try {
      const { ok, payload } = await requestLimitOrderPlacement(
        price,
        direction,
        limitOrderSize,
        placementId,
      );

      if (!ok || !payload.summary) {
        if (
          showServerDisciplineBlockedPayload(payload, {
            direction,
            price,
            size: limitOrderSize,
            symbol: activeSymbol,
          })
        ) {
          return false;
        }

        showToast(
          formatExecutionErrorMessage(
            payload.error ?? "unable to place testnet limit order",
          ),
        );
        return false;
      }

      const summary = payload.summary;

      if (summary.finalResult === "filled") {
        registerTradesPlaced(1);
        const relatedLogs = appendSessionLogEntries([
          {
            category: "orders",
            description: `${direction === "long" ? "Limit Buy" : "Limit Sell"} executed on placement.`,
            direction: summary.direction,
            eventType: "limit-order-placed",
            metadata: {
              limitOrderId: summary.limitOrder.id,
              placementId: summary.placementId,
            },
            pnl: null,
            price: summary.fillPrice,
            size: summary.actualFilledSize,
            source: getPendingOrderSourceLabel(source),
            symbol: summary.symbol,
          },
          {
            category: "positions",
            description: "Position opened from limit order execution.",
            direction: summary.direction,
            eventType: "position-opened",
            metadata: {
              limitOrderId: summary.limitOrder.id,
              placementId: summary.placementId,
            },
            pnl: null,
            price: summary.fillPrice,
            size: summary.actualFilledSize,
            source: getPendingOrderSourceLabel(source),
            symbol: summary.symbol,
          },
        ]);
        createOrUpdateJournalEntryForOrderFill({
          ...getJournalEntryClassification({ orderSource: source }),
          direction: summary.direction,
          entryPrice: summary.fillPrice,
          executionId: summary.placementId,
          orderId: summary.limitOrder.id,
          relatedSessionLogIds: relatedLogs.map((entry) => entry.id),
          size: summary.actualFilledSize,
          symbol: summary.symbol,
          timestamp: new Date(summary.timestamp).toISOString(),
        });
        setActivePosition({
          createdAt: new Date(summary.timestamp).toISOString(),
          direction: summary.direction,
          entry: summary.fillPrice,
          entryOrderId: summary.limitOrder.id,
          executionId: summary.placementId,
          id: `${summary.symbol}-position-${summary.placementId}`,
          size: summary.actualFilledSize,
          symbol: summary.symbol,
        });
        upsertConfirmedFillPosition({
          actualFilledSize: summary.actualFilledSize,
          direction: summary.direction,
          entryOrderId: summary.limitOrder.id,
          executionId: summary.placementId,
          fillPrice: summary.fillPrice,
          finalResult: summary.finalResult,
          intendedSize: summary.intendedSize,
          normalizedSize: summary.normalizedSize,
          symbol: summary.symbol,
          timestamp: summary.timestamp,
        });
        setActiveTradePlan(null);
        setDraftTradePlan(null);
        setSelectedObject(null);
        showOrderToast(
          "filled",
          "Limit order placed",
          undefined,
          0,
          buildLimitOrderToastReceipt({
            direction: summary.direction,
            price: summary.fillPrice,
            size: summary.actualFilledSize,
            symbol: summary.symbol,
          }),
        );
        void refreshPostMutationLiveState();
        return true;
      }

      registerTradesPlaced(1);
      appendSessionLogEntries([
        {
          category: "orders",
          description: `${direction === "long" ? "Limit Buy" : "Limit Sell"} placed and waiting on Hyperliquid.`,
          direction: summary.direction,
          eventType: "limit-order-placed",
          pnl: null,
          price: summary.normalizedPrice,
          size: summary.normalizedSize,
          source: getPendingOrderSourceLabel(source),
          symbol: summary.symbol,
        },
      ]);
      setPendingLimitOrders((currentOrders) => [
        ...currentOrders,
        buildPendingLimitOrder(summary, source, parentZoneId, metadata),
      ]);
      setActiveTradePlan(null);
      setDraftTradePlan(null);
      setSelectedObject(null);
      showOrderToast(
        "armed",
        "Limit order placed",
        undefined,
        0,
        buildLimitOrderToastReceipt({
          direction: summary.direction,
          price: summary.normalizedPrice,
          size: summary.normalizedSize,
          symbol: summary.symbol,
        }),
      );
      void refreshPostMutationLiveState();
      return true;
    } catch {
      showOrderToast(
        "rejected",
        "Limit order rejected",
        "Connection unavailable.",
      );
      return false;
    } finally {
      setIsExecuting(false);
      setLimitOrderRequestState("idle");
      setLimitPlacementDirection(null);
      setLimitOrderToastContext(null);
    }
  }

  async function handleOrderZoneCreate(
    zoneId: string,
    direction: TradeDirection,
    count: number,
    distribution: OrderZoneDistribution,
  ): Promise<boolean> {
    if (isChartOnlyMarketSymbol(activeSymbol)) {
      showOrderToast(
        "blocked",
        "Chart-only index",
        "Use this as a Magic Trade trigger source.",
      );
      return false;
    }

    const orderZoneSize = getExecutableMarketSizeForSymbol(
      activeSymbol as HyperliquidSymbol,
      direction,
    );

    const activeZone = chartZones.find(
      (zone) => zone.id === zoneId && zone.symbol === activeSymbol,
    );

    if (!activeZone) {
      showOrderToast(
        "rejected",
        "Order Zone rejected",
        "Zone is no longer available.",
      );
      return false;
    }

    const placementGuard = evaluateLimitOrderPlacementGuard(
      { direction, reduceOnly: false },
      getActiveSymbolLivePositionSnapshot(),
    );

    if (!placementGuard.allowed) {
      showOrderToast("blocked", "Order Zone blocked", placementGuard.reason);
      return false;
    }

    if (isExecuting) {
      showOrderToast(
        "blocked",
        "Execution blocked",
        "Request already in progress.",
      );
      return false;
    }

    if (orderZoneSize <= 0) {
      showOrderToast("blocked", "Order Zone blocked", "Size is too small.");
      return false;
    }

    const normalizedCount = Math.max(2, Math.min(10, Math.floor(count)));
    const perOrderSize = orderZoneSize / normalizedCount;
    const zonePrices = getOrderZonePrices(
      activeZone,
      normalizedCount,
      distribution,
    );
    const orderZoneLeverage = getSelectedTradeLeverageForSymbol(
      activeSymbol as HyperliquidSymbol,
    );
    const orderZoneNotional = zonePrices.reduce(
      (total, price) => total + price * perOrderSize,
      0,
    );
    const marginBlockReason = getMagicTradeMarginAllocationBlockReason({
      actionLabel: "Order Zone",
      direction,
      requestedMarginUsd:
        orderZoneLeverage > 0 ? orderZoneNotional / orderZoneLeverage : null,
    });

    if (marginBlockReason) {
      showToast(marginBlockReason, 0, "neutral");
      return false;
    }

    const disciplineDecision = evaluateCurrentDisciplineRiskGate({
      actionType: "order_zone_create",
      currentPosition: getActiveSymbolLivePositionSnapshot(),
      nextOrders: zonePrices.map((price, index) => ({
        id: `order-zone-preview-${index}`,
        side: direction,
        size: perOrderSize,
      })),
      noTradeZoneActive: zonePrices.some((price) =>
        isPriceInsideNoTradeZone(price),
      ),
      orderType: "limit",
      requestedTrades: normalizedCount,
      side: direction,
      size: perOrderSize * normalizedCount,
      source: "order_zone",
      symbol: activeSymbol,
    });

    if (disciplineDecision.decision === "blocked") {
      showDisciplineRiskGateBlockedToast(disciplineDecision, {
        direction,
        price: zonePrices[0] ?? null,
        size: perOrderSize * normalizedCount,
      });
      return false;
    }

    setDockTradeDirection(direction);
    setLimitOrderRequestState("placing");
    setIsExecuting(true);

    const placementOrders = zonePrices.map((price, index) => ({
      placementId: `order-zone-${Date.now()}-${index}-${crypto.randomUUID()}`,
      price,
      size: perOrderSize,
    }));

    try {
      const response = await fetch("/api/order-zone", {
        body: JSON.stringify({
          direction,
          distribution,
          orders: placementOrders,
          symbol: activeSymbol,
        }),
        headers: {
          "Content-Type": "application/json",
        },
        method: "POST",
      });

      const payload = (await response.json()) as {
        error?: string;
        summary?: OrderZonePlacementSummary;
      } & ServerDisciplineBlockedPayload;

      if (!response.ok || !payload.summary) {
        if (
          showServerDisciplineBlockedPayload(payload, {
            direction,
            price: zonePrices[0] ?? null,
            size: perOrderSize * normalizedCount,
            symbol: activeSymbol,
          })
        ) {
          return false;
        }

        showToast(
          formatExecutionErrorMessage(
            payload.error ?? "unable to place testnet order zone",
          ),
        );
        return false;
      }

      const summary = payload.summary;
      const liveOrders = summary.liveOrders.map((liveOrder) =>
        buildPendingLimitOrder(liveOrder, "order-zone", zoneId, {
          orderZoneCount: normalizedCount,
          orderZoneDistribution: distribution,
          orderZoneIndex: placementOrders.findIndex(
            (placementOrder) =>
              placementOrder.placementId === liveOrder.placementId,
          ),
        }),
      );
      const filledSummaries = summary.filledOrders;
      const failedCount = summary.rejectedOrders.length;
      const successfulOrderCount = liveOrders.length + filledSummaries.length;

      if (successfulOrderCount > 0) {
        registerTradesPlaced(successfulOrderCount);
      }

      if (liveOrders.length > 0) {
        appendSessionLogEntries(
          liveOrders.map((liveOrder) => ({
            category: "orders" as const,
            description: `${liveOrder.direction === "long" ? "Limit Buy" : "Limit Sell"} placed from the order zone ladder.`,
            direction: liveOrder.direction,
            eventType: "limit-order-placed" as const,
            pnl: null,
            price: liveOrder.normalizedPrice,
            size: liveOrder.normalizedSize,
            source: "Order Zone",
            symbol: liveOrder.symbol,
          })),
        );
      }

      if (filledSummaries.length > 0) {
        const firstFill = filledSummaries[0];
        const relatedLogs = appendSessionLogEntries(
          filledSummaries.map((fill, index) => ({
            category: "positions" as const,
            description:
              index === 0
                ? "Position opened from an order zone fill."
                : "Additional order zone child fill attached to the open position.",
            direction: fill.direction,
            eventType:
              index === 0
                ? ("position-opened" as const)
                : ("pending-order-filled" as const),
            metadata: {
              childOrderId: fill.limitOrder.id,
              limitOrderId: fill.limitOrder.id,
              orderZoneCount: normalizedCount,
              orderZoneDistribution: distribution,
              orderZoneId: zoneId,
              orderZoneIndex: placementOrders.findIndex(
                (placementOrder) =>
                  placementOrder.placementId === fill.placementId,
              ),
              placementId: fill.placementId,
              source: "order_zone",
            },
            pnl: null,
            price: fill.fillPrice,
            size: fill.actualFilledSize,
            source: "Order Zone",
            symbol: fill.symbol,
            timestamp: new Date(fill.timestamp).toISOString(),
          })),
        );
        createOrUpdateJournalEntryForOrderFill({
          ...getJournalEntryClassification({ orderSource: "order-zone" }),
          additionalOrderFills: filledSummaries
            .slice(1)
            .map((fill, fillIndex) => {
              const relatedLog = relatedLogs[fillIndex + 1];
              return {
                childOrderId: fill.limitOrder.id,
                executionId: fill.placementId,
                fillPrice: fill.fillPrice,
                fillSize: fill.actualFilledSize,
                orderId: fill.limitOrder.id,
                orderZoneId: zoneId,
                relatedSessionLogIds: relatedLog ? [relatedLog.id] : [],
                timestamp: new Date(fill.timestamp).toISOString(),
              };
            }),
          direction: firstFill.direction,
          entryPrice: firstFill.fillPrice,
          executionId: firstFill.placementId,
          metadata: {
            childOrderId: firstFill.limitOrder.id,
            orderZoneId: zoneId,
            source: "order_zone",
          },
          orderId: firstFill.limitOrder.id,
          orderZoneId: zoneId,
          relatedSessionLogIds: relatedLogs.map((entry) => entry.id),
          size: firstFill.actualFilledSize,
          symbol: firstFill.symbol,
          timestamp: new Date(firstFill.timestamp).toISOString(),
        });
        setActivePosition({
          createdAt: new Date(firstFill.timestamp).toISOString(),
          direction: firstFill.direction,
          entry: firstFill.fillPrice,
          entryOrderId: firstFill.limitOrder.id,
          executionId: firstFill.placementId,
          id: `${firstFill.symbol}-position-${firstFill.placementId}`,
          size: firstFill.actualFilledSize,
          symbol: firstFill.symbol,
        });
        upsertConfirmedFillPosition({
          actualFilledSize: firstFill.actualFilledSize,
          direction: firstFill.direction,
          entryOrderId: firstFill.limitOrder.id,
          executionId: firstFill.placementId,
          fillPrice: firstFill.fillPrice,
          finalResult: firstFill.finalResult,
          intendedSize: firstFill.intendedSize,
          normalizedSize: firstFill.normalizedSize,
          symbol: firstFill.symbol,
          timestamp: firstFill.timestamp,
        });
        setActiveTradePlan(null);
        setDraftTradePlan(null);
      }

      if (liveOrders.length > 0) {
        setPendingLimitOrders((currentOrders) => [
          ...currentOrders,
          ...liveOrders,
        ]);
      }

      setSelectedObject(null);
      void refreshPostMutationLiveState();

      if (
        failedCount > 0 &&
        liveOrders.length === 0 &&
        filledSummaries.length === 0
      ) {
        showOrderToast(
          "rejected",
          "Order Zone rejected",
          "No ladder orders were accepted.",
        );
        return false;
      }

      if (filledSummaries.length > 0 && liveOrders.length > 0) {
        updateZoneDerivedOrderConfig(zoneId, {
          count: normalizedCount,
          direction,
          distribution,
          type: "order-zone",
        });
        showOrderToast(
          "armed",
          "Order Zone active",
          `${liveOrders.length} live, ${filledSummaries.length} filled.`,
        );
        return true;
      }

      if (filledSummaries.length > 0) {
        updateZoneDerivedOrderConfig(zoneId, {
          count: normalizedCount,
          direction,
          distribution,
          type: "order-zone",
        });
        showOrderToast(
          "filled",
          "Order Zone filled",
          `${filledSummaries.length} order${filledSummaries.length === 1 ? "" : "s"} entered.`,
        );
        return true;
      }

      updateZoneDerivedOrderConfig(zoneId, {
        count: normalizedCount,
        direction,
        distribution,
        type: "order-zone",
      });
      showOrderToast(
        "armed",
        "Order Zone armed",
        `${liveOrders.length} pending order${liveOrders.length === 1 ? "" : "s"} live.`,
      );
      return true;
    } catch {
      showOrderToast(
        "rejected",
        "Order Zone rejected",
        "Connection unavailable.",
      );
      return false;
    } finally {
      setIsExecuting(false);
      setLimitOrderRequestState("idle");
    }
  }

  async function handleZoneDerivedOrderConfigure(
    zoneId: string,
    type: "mid-zone" | "order-zone",
    direction: TradeDirection,
    count: number,
    distribution: OrderZoneDistribution,
  ): Promise<boolean> {
    const linkedZoneOrders = pendingLimitOrdersRef.current.filter(
      (order) =>
        order.parentZoneId === zoneId &&
        (order.source === "mid-zone" || order.source === "order-zone"),
    );

    if (
      linkedZoneOrders.some(
        (order) => order.status === "canceling" || order.status === "updating",
      )
    ) {
      showOrderToast(
        "blocked",
        "Zone update blocked",
        "Linked orders are still processing.",
      );
      return false;
    }

    const previousZone = chartZones.find((zone) => zone.id === zoneId) ?? null;

    if (linkedZoneOrders.length > 0) {
      const didCancelLinkedZoneOrders = await cancelZoneLinkedOrders(zoneId, {
        failureMessage:
          "Zone update failed — old linked orders could not be canceled",
      });

      if (!didCancelLinkedZoneOrders) {
        return false;
      }
    }

    const didCreate =
      type === "mid-zone"
        ? await handleMidZoneLimitOrderCreate(zoneId, direction)
        : await handleOrderZoneCreate(zoneId, direction, count, distribution);

    if (!didCreate && previousZone) {
      updateZoneDerivedOrderConfig(zoneId, {
        count: previousZone.orderZoneCount ?? null,
        direction: previousZone.derivedOrderDirection ?? null,
        distribution: previousZone.orderZoneDistribution ?? null,
        type: previousZone.derivedOrderType ?? null,
      });
    }

    return didCreate;
  }

  function setDockTradeDirection(direction: TradeDirection) {
    setSelectedTradeDirection(direction);
  }

  function selectLimitPriceEntryMode(mode: LimitPriceEntryMode) {
    setLimitPriceEntryMode(mode);

    if (mode === "typed") {
      setLimitPlacementDirection(null);
      return;
    }

    setLimitPlacementDirection(selectedTradeDirection);
  }

  function fillTypedLimitPriceFromMid() {
    if (!limitMidPriceInput) {
      showToast("Mid price unavailable for this market", 0, "neutral");
      return;
    }

    setTypedLimitPriceInput(limitMidPriceInput);
  }

  async function handleTypedLimitOrderPlacement(
    price: number,
    direction: TradeDirection,
  ) {
    const didPlace = await handleLimitOrderPlacement(price, direction);

    if (didPlace) {
      setTypedLimitPriceInput("");
    }
  }

  function handlePrimaryTradeAction() {
    setDockTradeDirection(selectedTradeDirection);

    if (activeMarketIsChartOnly) {
      showOrderToast(
        "blocked",
        "Chart-only index",
        "Use this as a Magic Trade trigger source.",
      );
      return;
    }

    if (isLimitExecutionMode) {
      const resolution = resolveLimitPriceEntry({
        mode: limitPriceEntryMode,
        typedPriceInput: typedLimitPriceInput,
      });

      if (resolution.mode === "chart") {
        setLimitPlacementDirection(selectedTradeDirection);
        showToast("Select a limit level on the chart", 0, "neutral");
        return;
      }

      if (!resolution.ok) {
        showToast(resolution.reason, 0, "neutral");
        return;
      }

      void handleTypedLimitOrderPlacement(
        resolution.price,
        selectedTradeDirection,
      );
      return;
    }

    void handleMarketExecution(selectedTradeDirection);
  }

  function handleDockDirectionSelection(direction: TradeDirection) {
    setDockTradeDirection(direction);
    setLimitPlacementDirection((currentDirection) =>
      currentDirection === null ? null : direction,
    );
  }

  function openTradeLeverageModal() {
    setIsTradeMarginModeDrawerOpen(false);
    setIsAccountUnificationModeDrawerOpen(false);
    setDraftTradeLeverage(selectedTradeLeverage);
    setIsTradeLeverageModalOpen(true);
  }

  function openMarketMaxSlippageModal() {
    setIsTradeMarginModeDrawerOpen(false);
    setIsAccountUnificationModeDrawerOpen(false);
    setMarketMaxSlippageDraft(marketMaxSlippagePercent.toFixed(2));
    setIsMarketMaxSlippageModalOpen(true);
  }

  function toggleTradeMarginModeDrawer() {
    setIsAccountUnificationModeDrawerOpen(false);
    setIsTradeMarginModeDrawerOpen((isOpen) => !isOpen);
  }

  function selectTradeMarginMode(nextMode: TradeMarginMode) {
    setTradeMarginModeBySymbol((currentMarginModeBySymbol) => ({
      ...currentMarginModeBySymbol,
      [activeSymbol]: nextMode,
    }));
    setIsTradeMarginModeDrawerOpen(false);
  }

  function toggleAccountUnificationModeDrawer() {
    setIsTradeMarginModeDrawerOpen(false);
    setIsAccountUnificationModeDrawerOpen((isOpen) => !isOpen);
  }

  function selectAccountUnificationMode(nextMode: AccountUnificationMode) {
    setAccountUnificationMode(nextMode);
    setIsAccountUnificationModeDrawerOpen(false);
  }

  function applyTradeLeverageChange() {
    const nextLeverage = clampMagicTradeLeverage(
      draftTradeLeverage,
      selectedTradeMaxLeverage,
    );

    setTradeLeverageBySymbol((currentLeverageBySymbol) => ({
      ...currentLeverageBySymbol,
      [activeSymbol]: nextLeverage,
    }));
    setIsTradeLeverageModalOpen(false);
  }

  function applyMarketMaxSlippageChange() {
    if (marketMaxSlippageDraftError !== null) {
      return;
    }

    const nextMaxSlippage = normalizeMarketMaxSlippagePercent(
      marketMaxSlippageDraftValue,
    );

    setMarketMaxSlippagePercent(nextMaxSlippage);
    setMarketMaxSlippageDraft(nextMaxSlippage.toFixed(2));
    setIsMarketMaxSlippageModalOpen(false);
  }

  function getSelectedTradeLeverageForSymbol(symbol: HyperliquidSymbol) {
    const maxLeverage =
      getMagicTradeMaxLeverageInt(
        marketMetadataBySymbol[symbol]?.maxLeverage,
      ) ?? 1;
    const liveLeverage = liveExchangePositionsRef.current.find(
      (position) => position.symbol === symbol,
    )?.leverageValue;

    return clampMagicTradeLeverage(
      tradeLeverageBySymbol[symbol] ?? liveLeverage ?? maxLeverage,
      maxLeverage,
    );
  }

  function getSelectedTradeMarginModeForSymbol(
    symbol: HyperliquidSymbol,
  ): TradeMarginMode {
    return tradeMarginModeBySymbol[symbol] ?? "cross";
  }

  function getExecutableMarketSizeForSymbol(
    symbol: HyperliquidSymbol,
    direction: TradeDirection,
  ) {
    if (isChartOnlyMarketSymbol(symbol)) {
      return 0;
    }

    const livePrice =
      marketPrices[symbol] ?? currentPriceBySymbolRef.current[symbol] ?? null;

    if (!Number.isFinite(livePrice) || livePrice === null || livePrice <= 0) {
      return 0;
    }

    return normalizeExecutionSize(
      getSelectedPositionNotionalForDirection(direction, symbol) / livePrice,
      symbol,
    );
  }

  async function executeMarketOrder(
    direction: TradeDirection,
    options: {
      confirmedDisciplineWarnings?: DisciplineRiskGateReasonCode[];
      ignorePendingOrders?: boolean;
      journalEntryClassification?: {
        entrySource: JournalEntrySource;
        entryStyle: JournalEntryStyle;
      };
      executionSizing?: {
        allocationPercent: number | null;
        baseSize: number;
        conversionPrice: number | null;
        intendedNotionalUsdc: number | null;
      };
      statusMessage?: string;
      successMessage?: string;
      riskActionSource?: DisciplineRiskActionSource;
      riskActionType?: DisciplineRiskActionType;
      symbol?: HyperliquidSymbol;
      triggerId?: string;
    } = {},
  ) {
    const symbol = options.symbol ?? (activeSymbol as HyperliquidSymbol);

    if (isChartOnlyMarketSymbol(symbol)) {
      showOrderToast(
        "blocked",
        "Chart-only index",
        "Use this as a Magic Trade trigger source.",
      );
      return false;
    }

    if (isExecuting) {
      showOrderToast(
        "blocked",
        "Execution blocked",
        "Request already in progress.",
      );
      return false;
    }

    const pendingOrderBlockReason = getPendingOrderMarketExecutionBlockReason({
      ignorePendingOrders: Boolean(options.ignorePendingOrders),
      pendingOrderCount: pendingLimitOrdersRef.current.length,
    });

    if (pendingOrderBlockReason !== null) {
      showOrderToast("blocked", "Execution blocked", pendingOrderBlockReason);
      return false;
    }

    setDockTradeDirection(direction);

    const marketSize =
      options.executionSizing?.baseSize ??
      getExecutableMarketSizeForSymbol(symbol, direction);

    if (marketSize <= 0) {
      showOrderToast("blocked", "Market order blocked", "Invalid order size.");
      return false;
    }

    const conversionPrice =
      options.executionSizing?.conversionPrice ??
      marketPrices[symbol] ??
      currentPriceBySymbolRef.current[symbol] ??
      null;
    const intendedNotionalUsdc =
      options.executionSizing?.intendedNotionalUsdc ??
      getSelectedPositionNotionalForDirection(direction, symbol);
    const allocationPercent =
      options.executionSizing?.allocationPercent ??
      (symbol === activeSymbolRef.current ? collateralAllocationPercent : null);
    const executionLeverage = getSelectedTradeLeverageForSymbol(symbol);
    const requestedMarginUsd =
      intendedNotionalUsdc !== null &&
      Number.isFinite(intendedNotionalUsdc) &&
      executionLeverage > 0
        ? intendedNotionalUsdc / executionLeverage
        : null;
    const marginBlockReason = getMagicTradeMarginAllocationBlockReason({
      actionLabel:
        options.riskActionSource === "trigger"
          ? "Trigger execution"
          : "Execution",
      direction,
      requestedMarginUsd,
    });

    if (marginBlockReason) {
      showToast(marginBlockReason, 0, "neutral");
      return false;
    }

    const sizingCheck = resolveExecutionSizing({
      baseSize: marketSize,
      conversionPrice,
      intendedNotionalUsdc,
      symbol,
    });

    if (!sizingCheck.ok) {
      showOrderToast(
        "blocked",
        "Market order blocked",
        formatExecutionErrorMessage(sizingCheck.error),
      );
      return false;
    }

    const sizingMetadata = getExecutionSizingMetadata({
      allocationPercent,
      baseSize: sizingCheck.baseSize,
      conversionPrice,
      intendedNotionalUsdc,
    });

    const disciplineDecision = evaluateCurrentDisciplineRiskGate({
      actionType: options.riskActionType ?? "market_order",
      confirmedDisciplineWarnings: options.confirmedDisciplineWarnings,
      currentPosition:
        liveExchangePositionsRef.current.find(
          (position) => position.symbol === symbol,
        ) ??
        (activePositionRef.current?.symbol === symbol
          ? activePositionRef.current
          : null),
      orderType: "market",
      requestedTrades: 1,
      side: direction,
      size: marketSize,
      source: options.riskActionSource ?? "manual",
      symbol,
    });

    if (disciplineDecision.decision === "blocked") {
      showDisciplineRiskGateBlockedToast(disciplineDecision, {
        direction,
        metadata: {
          triggerId: options.triggerId,
          triggerSource:
            options.riskActionSource === "trigger" ? "chart_line" : undefined,
        },
        price:
          marketPrices[symbol] ??
          currentPriceBySymbolRef.current[symbol] ??
          null,
        size: marketSize,
      });
      return false;
    }

    const executionId = `exec-${Date.now()}-${crypto.randomUUID()}`;
    setIsExecuting(true);
    setExecutionStatusMessage(
      options.statusMessage ??
        (direction === "long"
          ? "Processing market buy"
          : "Processing market sell"),
    );

    try {
      const result = await placeHyperliquidMarketOrder({
        allocationPercent: sizingMetadata.allocationPercent,
        baseSize: sizingCheck.baseSize,
        confirmedDisciplineWarnings: options.confirmedDisciplineWarnings,
        conversionPrice,
        executionId,
        intendedNotionalUsdc,
        leverage: executionLeverage,
        marginMode: getSelectedTradeMarginModeForSymbol(symbol),
        maxSlippagePercent: marketMaxSlippagePercent,
        side: direction,
        symbol,
      });

      latestExecutionSummaryRef.current = result.ok
        ? result.summary
        : (result.summary ?? null);
      console.debug(
        "[portal] execution summary",
        latestExecutionSummaryRef.current ?? { executionId },
      );

      if (!result.ok) {
        if (
          showServerDisciplineBlockedPayload(
            {
              discipline:
                result.discipline as ServerDisciplineBlockedPayload["discipline"],
              disciplineLogEntry:
                result.disciplineLogEntry as ServerDisciplineBlockedPayload["disciplineLogEntry"],
              error: result.error,
            },
            {
              direction,
              price:
                marketPrices[symbol] ??
                currentPriceBySymbolRef.current[symbol] ??
                null,
              size: marketSize,
              symbol,
            },
          )
        ) {
          return false;
        }

        showToast(formatExecutionErrorMessage(result.error));
        return false;
      }

      const summary = result.summary;
      registerTradesPlaced(1);
      const relatedLogs = appendSessionLogEntries([
        {
          category: "positions",
          description: `${direction === "long" ? "Market Buy" : "Market Sell"} filled on Hyperliquid.`,
          direction: summary.direction,
          eventType: "position-opened",
          metadata: {
            ...sizingMetadata,
            entryOrderId: summary.entryOrder.id,
            executionId: summary.executionId,
            triggerId: options.triggerId,
            triggerSource:
              options.riskActionSource === "trigger" ? "chart_line" : undefined,
          },
          pnl: null,
          price: summary.fillPrice,
          size: summary.actualFilledSize,
          source: "Trade Dock",
          symbol: summary.symbol,
        },
      ]);
      createOrUpdateJournalEntryForOrderFill({
        ...(options.journalEntryClassification ??
          getJournalEntryClassification({ triggerSource: "market-manual" })),
        direction: summary.direction,
        entryPrice: summary.fillPrice,
        executionId: summary.executionId,
        metadata: {
          ...sizingMetadata,
          triggerId: options.triggerId,
          triggerSource:
            options.riskActionSource === "trigger" ? "chart_line" : undefined,
        },
        orderId: summary.entryOrder.id,
        relatedSessionLogIds: relatedLogs.map((entry) => entry.id),
        size: summary.actualFilledSize,
        symbol: summary.symbol,
        timestamp: new Date(summary.timestamp).toISOString(),
      });
      setActivePosition({
        createdAt: new Date(summary.timestamp).toISOString(),
        direction: summary.direction,
        entry: summary.fillPrice,
        entryOrderId: summary.entryOrder.id,
        executionId: summary.executionId,
        id: `${summary.symbol}-position-${summary.executionId}`,
        size: summary.actualFilledSize,
        symbol: summary.symbol,
      });
      upsertConfirmedExecutionPosition(summary);
      setActiveTradePlan(null);
      setDraftTradePlan(null);
      setSelectedObject(null);
      setCommandValue("");
      if (options.successMessage) {
        showOrderToast("filled", options.successMessage);
      } else {
        showOrderToast(
          "filled",
          `${direction === "long" ? "Market Buy" : "Market Sell"} filled`,
          "Entry line anchored to fill.",
        );
      }
      void refreshPostMutationLiveState();
      return true;
    } catch {
      showOrderToast(
        "rejected",
        "Market order rejected",
        "Connection unavailable.",
      );
      return false;
    } finally {
      setIsExecuting(false);
      setExecutionStatusMessage(null);
    }
  }

  async function fireLineTrigger(trigger: ChartLineTrigger) {
    if (firingLineTriggerIdsRef.current[trigger.id]) {
      return;
    }

    const triggerStillExists = chartLevelsRef.current.some(
      (level) => level.id === trigger.targetId,
    );

    if (!triggerStillExists) {
      setChartLineTriggers((currentTriggers) =>
        currentTriggers.filter(
          (currentTrigger) => currentTrigger.id !== trigger.id,
        ),
      );
      return;
    }

    firingLineTriggerIdsRef.current[trigger.id] = true;
    chartLineTriggersRef.current = chartLineTriggersRef.current.map(
      (currentTrigger) =>
        currentTrigger.id === trigger.id
          ? {
              ...currentTrigger,
              status: "firing",
            }
          : currentTrigger,
    );
    setChartLineTriggers((currentTriggers) =>
      currentTriggers.map((currentTrigger) =>
        currentTrigger.id === trigger.id
          ? {
              ...currentTrigger,
              status: "firing",
            }
          : currentTrigger,
      ),
    );

    await executeMarketOrder(trigger.direction, {
      ignorePendingOrders: true,
      journalEntryClassification: getJournalEntryClassification({
        triggerCondition: trigger.condition,
      }),
      riskActionSource: "trigger",
      riskActionType: "trigger_market_order",
      statusMessage:
        trigger.direction === "long"
          ? "Triggering market buy..."
          : "Triggering market sell...",
      successMessage: `${trigger.direction === "long" ? "Trigger Buy" : "Trigger Sell"} fired — entry line anchored to fill`,
      symbol: trigger.symbol as HyperliquidSymbol,
      triggerId: trigger.id,
    });

    setChartLineTriggers((currentTriggers) =>
      currentTriggers.filter(
        (currentTrigger) => currentTrigger.id !== trigger.id,
      ),
    );
    chartLineTriggersRef.current = chartLineTriggersRef.current.filter(
      (currentTrigger) => currentTrigger.id !== trigger.id,
    );
    delete firingLineTriggerIdsRef.current[trigger.id];
  }

  async function handleMarketExecution(direction: TradeDirection) {
    await executeMarketOrder(direction);
  }

  function scheduleZoneStateReset(
    zoneId: string,
    nextState: ChartZoneState,
    delay: number,
  ) {
    const existingTimer = zoneStateTimersRef.current[zoneId];

    if (existingTimer) {
      window.clearTimeout(existingTimer);
    }

    zoneStateTimersRef.current[zoneId] = window.setTimeout(() => {
      setChartZones((currentZones) =>
        currentZones.map((zone) =>
          zone.id === zoneId
            ? {
                ...zone,
                state: nextState,
              }
            : zone,
        ),
      );
      delete zoneStateTimersRef.current[zoneId];
    }, delay);
  }

  function handleCurrentPriceChange(currentPrice: number) {
    const priceUpdatedAt = Date.now();
    currentPriceBySymbolRef.current[activeSymbol] = currentPrice;
    const previousPrice = previousPriceBySymbolRef.current[activeSymbol];
    previousPriceBySymbolRef.current[activeSymbol] = currentPrice;
    currentPriceUpdatedAtBySymbolRef.current[activeSymbol] = priceUpdatedAt;
    setMarketPrices((currentPrices) =>
      currentPrices[activeSymbol] === currentPrice
        ? currentPrices
        : {
            ...currentPrices,
            [activeSymbol]: currentPrice,
          },
    );

    if (!isExecuting && previousPrice !== null && previousPrice !== undefined) {
      const currentTimeSeconds = Math.floor(Date.now() / 1000);
      const previousTimeSeconds = currentTimeSeconds - 1;
      const armedTrigger = chartLineTriggersRef.current.find((trigger) => {
        if (trigger.symbol !== activeSymbol || trigger.status !== "armed") {
          return false;
        }

        if (trigger.condition !== "touch") {
          return false;
        }

        const levelPrice =
          chartLevelsRef.current.find((level) => level.id === trigger.targetId)
            ?.price ?? null;

        if (levelPrice === null) {
          return false;
        }

        if (restoredTriggerIdsRef.current[trigger.id]) {
          delete restoredTriggerIdsRef.current[trigger.id];
          return false;
        }

        const previousReferencePrice = levelPrice;
        const currentReferencePrice = levelPrice;

        if (previousReferencePrice === null && currentReferencePrice === null) {
          return false;
        }

        const previousComparablePrice =
          previousReferencePrice ?? currentReferencePrice ?? levelPrice;
        const currentComparablePrice =
          currentReferencePrice ?? previousReferencePrice ?? levelPrice;
        const crossingThreshold = Math.max(
          Math.abs(currentComparablePrice) * 0.000005,
          0.1,
        );
        const touched =
          Math.abs(currentPrice - currentComparablePrice) <=
            crossingThreshold ||
          Math.abs(previousPrice - previousComparablePrice) <=
            crossingThreshold;
        const crossed =
          (previousPrice < previousComparablePrice &&
            currentPrice > currentComparablePrice) ||
          (previousPrice > previousComparablePrice &&
            currentPrice < currentComparablePrice) ||
          (previousPrice < previousComparablePrice &&
            currentPrice === currentComparablePrice) ||
          (previousPrice > previousComparablePrice &&
            currentPrice === currentComparablePrice);

        return touched || crossed;
      });

      if (armedTrigger) {
        void fireLineTrigger(armedTrigger);
      }
    }

    setChartZones((currentZones) =>
      currentZones.map((zone) => {
        if (zone.symbol !== activeSymbol) {
          return zone;
        }

        const topPrice = Math.max(zone.topPrice, zone.bottomPrice);
        const bottomPrice = Math.min(zone.topPrice, zone.bottomPrice);
        const inside = currentPrice >= bottomPrice && currentPrice <= topPrice;
        const distanceToZone = inside
          ? 0
          : currentPrice < bottomPrice
            ? bottomPrice - currentPrice
            : currentPrice - topPrice;
        const approachThreshold =
          currentPrice * ZONE_APPROACH_THRESHOLD_PERCENT;
        const approaching = !inside && distanceToZone <= approachThreshold;
        const wasInside = zone.state === "inside";
        let nextState: ChartZoneState = zone.state;
        let lastInteraction = zone.lastInteraction;

        if (inside) {
          const existingTimer = zoneStateTimersRef.current[zone.id];

          if (existingTimer) {
            window.clearTimeout(existingTimer);
            delete zoneStateTimersRef.current[zone.id];
          }

          if (!wasInside) {
            if (previousPrice !== null && previousPrice !== undefined) {
              if (previousPrice > topPrice) {
                zoneEntrySideRef.current[zone.id] = "above";
              } else if (previousPrice < bottomPrice) {
                zoneEntrySideRef.current[zone.id] = "below";
              }
            }

            lastInteraction = new Date().toISOString();
          }

          nextState = "inside";
        } else if (wasInside) {
          const entrySide = zoneEntrySideRef.current[zone.id];
          let exitedSide: ZoneEntrySide | null = null;

          if (currentPrice > topPrice) {
            exitedSide = "above";
          } else if (currentPrice < bottomPrice) {
            exitedSide = "below";
          }

          if (entrySide && exitedSide) {
            const interactionState: ChartZoneState =
              entrySide === exitedSide ? "rejected" : "broken";

            nextState = interactionState;
            lastInteraction = new Date().toISOString();
            scheduleZoneStateReset(
              zone.id,
              approaching ? "approaching" : "idle",
              interactionState === "broken"
                ? ZONE_BROKEN_HOLD_MS
                : ZONE_REJECTED_HOLD_MS,
            );
          } else {
            nextState = approaching ? "approaching" : "idle";
          }

          zoneEntrySideRef.current[zone.id] = null;
        } else if (zone.state === "rejected" || zone.state === "broken") {
          nextState = zone.state;
        } else {
          zoneEntrySideRef.current[zone.id] = null;
          nextState = approaching ? "approaching" : "idle";
        }

        if (
          nextState === zone.state &&
          lastInteraction === zone.lastInteraction
        ) {
          return zone;
        }

        return {
          ...zone,
          lastInteraction,
          state: nextState,
        };
      }),
    );
  }

  function resetBaselineImportWizard(options?: { keepBundle?: boolean }) {
    setBaselineImportWizardStep("source");
    setBaselineImportDraft(createDefaultBaselineImportDraft());
    setBaselineImportPreviewResult(null);
    setBaselineImportUploadedFiles([]);
    setBaselineImportUploadValidation(null);
    setBaselineImportError(null);
    setBaselineImportRequestState("idle");
  }

  function closeBaselineImportWizard() {
    setIsBaselineImportWizardOpen(false);
    resetBaselineImportWizard({ keepBundle: true });
  }

  function openBaselineImportWizard() {
    setBaselineImportWizardStep("source");
    setBaselineImportDraft((currentDraft) => {
      const defaultDraft = createDefaultBaselineImportDraft();
      return {
        ...defaultDraft,
        accountAddress: currentDraft.accountAddress,
        environment: currentDraft.environment,
      };
    });
    setBaselineImportPreviewResult(null);
    setBaselineImportUploadedFiles([]);
    setBaselineImportUploadValidation(null);
    setBaselineImportError(null);
    setBaselineImportRequestState("idle");
    setIsBaselineImportWizardOpen(true);
  }

  function goToPreviousBaselineImportStep() {
    const currentIndex = BASELINE_IMPORT_WIZARD_STEPS.indexOf(
      baselineImportWizardStep,
    );

    if (currentIndex <= 0) {
      return;
    }

    setBaselineImportWizardStep(
      BASELINE_IMPORT_WIZARD_STEPS[currentIndex - 1] ?? "source",
    );
  }

  function goToNextBaselineImportStep() {
    const currentIndex = BASELINE_IMPORT_WIZARD_STEPS.indexOf(
      baselineImportWizardStep,
    );

    if (currentIndex >= BASELINE_IMPORT_WIZARD_STEPS.length - 1) {
      return;
    }

    setBaselineImportWizardStep(
      BASELINE_IMPORT_WIZARD_STEPS[currentIndex + 1] ?? "save",
    );
  }

  async function handleManualHistoryFilesSelected(
    files: FileList | null,
  ) {
    const selectedFiles = Array.from(files ?? []);

    if (selectedFiles.length === 0) {
      setBaselineImportUploadedFiles([]);
      setBaselineImportUploadValidation(null);
      setBaselineImportPreviewResult(null);
      return;
    }

    setBaselineImportRequestState("previewing");
    setBaselineImportError(null);

    try {
      const uploadedFiles = await Promise.all(
        selectedFiles.map(async (file) => ({
          name: file.name,
          text: await file.text(),
        })),
      );
      const validation = parseManualHistoryImportFiles({
        files: uploadedFiles,
        timezone: getBrowserResolvedTimezone(),
      });

      setBaselineImportUploadedFiles(uploadedFiles);
      setBaselineImportUploadValidation(validation);
      setBaselineImportPreviewResult(null);
    } catch (error) {
      setBaselineImportError(
        error instanceof Error
          ? error.message
          : "Unable to read uploaded history files.",
      );
    } finally {
      setBaselineImportRequestState("idle");
    }
  }

  async function handleBaselineImportPreview() {
    if (baselineImportUploadedFiles.length === 0) {
      setBaselineImportError(
        "Upload Hyperliquid history files before confirming import.",
      );
      return;
    }

    setBaselineImportRequestState("previewing");
    setBaselineImportError(null);

    try {
      const result = runManualHistoryImportFromFiles({
        files: baselineImportUploadedFiles,
        timezone: getBrowserResolvedTimezone(),
      });
      setBaselineImportDraft((currentDraft) => ({
        ...currentDraft,
        accountAddress: result.request.accountAddress,
        endDate: formatDateInputValue(new Date(result.request.endTime)),
        environment: result.request.environment,
        startDate: formatDateInputValue(new Date(result.request.startTime)),
        timezone: result.request.timezone,
      }));
      setBaselineImportUploadValidation(result.parseResult);
      setBaselineImportPreviewResult(result.scanResult);
      setBaselineImportWizardStep("review");
    } catch (error) {
      setBaselineImportError(
        error instanceof Error ? error.message : "Manual history import failed.",
      );
    } finally {
      setBaselineImportRequestState("idle");
    }
  }

  async function handleBaselineImportSave() {
    if (!baselineImportRequest || !baselineImportPreviewResult) {
      setBaselineImportError("Confirm an uploaded import before saving it.");
      return;
    }

    setBaselineImportRequestState("saving");
    setBaselineImportError(null);

    try {
      const bundle: StoredBaselineImportBundle = {
        id: createStoredBaselineImportBundleId(baselineImportRequest),
        request: baselineImportRequest,
        result: baselineImportPreviewResult,
        savedAt: new Date().toISOString(),
        source: "hyperliquid",
        sourceLabel: "Historical Import",
        version: BASELINE_IMPORT_STORAGE_VERSION,
      };

      const nextBundles = [
        ...storedBaselineImportBundles.filter(
          (currentBundle) => currentBundle.id !== bundle.id,
        ),
        bundle,
      ].sort((left, right) => right.savedAt.localeCompare(left.savedAt));

      await persistStoredBaselineImportBundlesToLocalStore(
        window.localStorage,
        nextBundles,
      );
      setStoredBaselineImportBundles(nextBundles);
      setIsBaselineImportWizardOpen(false);
      resetBaselineImportWizard({ keepBundle: true });
      setOpenBaselineProfileId(bundle.id);
      showToast("Historical Import saved locally", 0, "success");
    } catch (error) {
      setBaselineImportError(
        error instanceof Error
          ? error.message
          : "Unable to save Historical Import.",
      );
    } finally {
      setBaselineImportRequestState("idle");
    }
  }

  async function handleRefreshBaselineImport() {
    if (!openBaselineProfileBundle) {
      return;
    }

    setBaselineImportRequestState("previewing");
    setBaselineImportError(null);

    try {
      const refreshedResult = await runHistoricalBaselineScan(
        openBaselineProfileBundle.request,
      );
      const refreshedBundle: StoredBaselineImportBundle = {
        ...openBaselineProfileBundle,
        result: refreshedResult,
        savedAt: new Date().toISOString(),
      };

      const nextBundles = storedBaselineImportBundles
        .map((bundle) =>
          bundle.id === refreshedBundle.id ? refreshedBundle : bundle,
        )
        .sort((left, right) => right.savedAt.localeCompare(left.savedAt));

      await persistStoredBaselineImportBundlesToLocalStore(
        window.localStorage,
        nextBundles,
      );
      setStoredBaselineImportBundles(nextBundles);
      showToast("Recent API scan refreshed", 0, "success");
    } catch (error) {
      setBaselineImportError(
        error instanceof Error
          ? error.message
          : "Unable to refresh recent API scan.",
      );
    } finally {
      setBaselineImportRequestState("idle");
    }
  }

  async function persistStoredBaselineImportBundles(
    nextBundles: StoredBaselineImportCollection,
  ) {
    await persistStoredBaselineImportBundlesToLocalStore(
      window.localStorage,
      nextBundles,
    );
    setStoredBaselineImportBundles(nextBundles);
  }

  async function deleteBaselineImportSource(bundleId: string) {
    const nextBundles = deleteStoredBaselineImportBundle(
      storedBaselineImportBundles,
      bundleId,
    );

    if (nextBundles.length === storedBaselineImportBundles.length) {
      return;
    }

    await persistStoredBaselineImportBundles(nextBundles);
    await deleteStoredBaselineImportBundlePayloads([bundleId]);
    setOpenBaselineProfileId((currentId) =>
      currentId === bundleId ? null : currentId,
    );
    showToast("Context source deleted", 0, "neutral");
  }

  function handleDeleteBaselineImport() {
    if (!openBaselineProfileBundle) {
      return;
    }

    void deleteBaselineImportSource(openBaselineProfileBundle.id);
  }

